// Structural data arrays (DEGREES, MODES, etc.) remain in the component for now.

export interface Question { q: string; opts: string[]; a: number; fb: string; }
export interface Cours6Locale { questions: Question[]; }

const questionsFr: Question[] = [
  // Centre tonal (20)
  { q:"Quelle est la première chose à analyser pour identifier le centre tonal ?", opts:["Le tempo","L'armure","La longueur","Le registre"], a:1, fb:"L'armure indique immédiatement les tonalités probables — la gamme majeure et sa relative mineure. C'est le premier repère de l'analyse tonale." },
  { q:"2 dièses (F# et C#) correspondent à la tonalité de :", opts:["G majeur ou E mineur","D majeur ou B mineur","A majeur ou F# mineur","B♭ majeur ou G mineur"], a:1, fb:"2 dièses = armure de D majeur / B mineur. F# et C# sont les altérations constitutives de ces deux gammes." },
  { q:"La sensible se reconnaît à :", opts:["Un saut de tierce","Un demi-ton ascendant vers une note stable","Une longue tenue","Un saut de quinte"], a:1, fb:"La sensible est le VIIe degré harmonique — elle monte d'un demi-ton vers la tonique. C'est l'attraction mélodique la plus forte de la gamme." },
  { q:"Une note tenue sur un temps fort en début de phrase correspond souvent à :", opts:["La dominante","Le VIIe degré","Le Ier ou VIe degré — pôles de stabilité","Une note étrangère"], a:2, fb:"Les notes stables sur les temps forts correspondent aux degrés I et VI — les pôles toniques. La mélodie s'y repose naturellement." },
  { q:"Une altération accidentelle prolongée sur plusieurs mesures indique :", opts:["Un emprunt ponctuel","Une modulation possible","Une erreur de notation","Un retard"], a:1, fb:"Altération ponctuelle = emprunt. Prolongée = le centre tonal peut avoir changé — signe d'une modulation vers une nouvelle tonalité." },
  { q:"La cadence finale est utile pour identifier le centre tonal car :", opts:["Elle est toujours V7–I","Elle révèle la résolution réelle — le degré I local","Elle utilise des rondes","Elle est toujours en majeur"], a:1, fb:"La cadence finale montre comment la phrase se résout. Le degré I de la cadence est le centre tonal local." },
  { q:"Le rythme harmonique est :", opts:["La vitesse du métronome","La fréquence de changement des accords","Le nombre de notes par mesure","Le type de mesure"], a:1, fb:"Le rythme harmonique est la fréquence à laquelle les accords changent — indépendamment du tempo." },
  { q:"Pourquoi toutes les notes d'une mélodie ne correspondent-elles pas nécessairement à l'accord ?", opts:["Car la mélodie peut être fausse","Car certaines sont des notes étrangères — ornements qui ne font pas partie de l'accord","Car l'accord est toujours renversé","Car les altérations changent tout"], a:1, fb:"La mélodie contient souvent des notes étrangères. Les identifier évite d'empiler des accords inutiles." },
  { q:"Les 'notes réelles' sont :", opts:["Les notes jouées en double","Les notes qui appartiennent à l'accord harmonique en cours","Les notes sans altération","Les notes de basse"], a:1, fb:"Les notes réelles appartiennent à l'accord — elles constituent la structure harmonique. Les autres ornent cette structure." },
  { q:"Un emprunt diffère d'une modulation car :", opts:["L'emprunt utilise des accords renversés","L'emprunt est momentané et ne déplace pas le centre tonal","L'emprunt suit toujours V7–I","L'emprunt utilise le napolitain"], a:1, fb:"Un emprunt est bref. Une modulation installe durablement une nouvelle tonalité — confirmée par une cadence parfaite dans le nouveau centre." },
  { q:"La tonalité de F majeur a combien de bémols ?", opts:["Aucun","Un (B♭)","Deux (B♭, E♭)","Trois"], a:1, fb:"F majeur a un bémol : Si♭ (B♭). C'est l'armure à un bémol — la gamme F G A B♭ C D E F." },
  { q:"La mélodie qui tourne autour de G et monte vers A♭ suggère :", opts:["C majeur","A♭ majeur ou F mineur","G majeur","D mineur"], a:1, fb:"G → A♭ est un demi-ton ascendant : G agit comme sensible de A♭. La tonalité est probablement A♭ majeur ou F mineur (relatif)." },
  { q:"Une tonalité mineure se distingue d'une majeure homonyme dans la mélodie par :", opts:["Son armure uniquement","La présence récurrente du IIIe degré mineur et de la sensible spécifique","Son tempo","Son registre"], a:1, fb:"En mineur, la mélodie gravite autour de la tierce mineure (Eb en C mineur) et de la sensible harmonique (B naturel). Ces notes caractérisent le mode mineur même sans armure." },
  { q:"Quelle mélodie suggère C majeur plutôt que A mineur ?", opts:["Une mélodie qui finit sur A","Une mélodie qui commence et finit sur C, avec des appuis fréquents sur E et G","Une mélodie avec beaucoup de notes graves","Une mélodie en triolets"], a:1, fb:"Si la mélodie s'ancre sur C (tonique), E (tierce) et G (quinte) et termine sur C, la tonalité est C majeur. Si elle s'ancre sur A, c'est A mineur." },
  { q:"Le rythme harmonique d'une ballade est typiquement :", opts:["Un accord par note","Un accord par mesure ou demi-mesure","Un accord par huitième","Aucun accord régulier"], a:1, fb:"Une ballade change d'accord lentement — souvent une fois par mesure. Chaque accord a le temps de s'installer dans l'oreille." },
  { q:"La tonicisation se reconnaît dans la mélodie à :", opts:["Une longue tenue","Une sensible artificielle — demi-ton ascendant vers un degré non-tonique","Un saut de quinte","Un retard"], a:1, fb:"Une tonicisation crée une sensible temporaire vers un accord non-tonique. Ex : C# (sensible de D) suivi de D dans une mélodie en G majeur = tonicisation de Dm." },
  { q:"Si la mélodie contient un F# dans une tonalité à 0 dièse, c'est probablement :", opts:["Une erreur","Une tonicisation de G (dont F# est la sensible) ou un emprunt","Une note de broderie","La fondamentale d'un accord"], a:1, fb:"En C majeur, F# est hors gamme. C'est probablement la sensible de G (V), créant une tonicisation V/V — ou un emprunt. La présence de G qui suit confirme la tonicisation." },
  { q:"Qu'est-ce qui différencie les 'points stables' des notes de passage dans une mélodie ?", opts:["Leur hauteur","Les points stables sont sur les temps forts et les degrés I/VI — les notes de passage relient des notes stables","Leur durée uniquement","Leur registre"], a:1, fb:"Points stables : temps forts, longues durées, degrés I et VI. Notes de passage : temps faibles, durées courtes, relient deux notes réelles. La position métrique est un indice clé." },
  { q:"Harmoniser chaque note avec un accord différent crée :", opts:["Une belle harmonie riche","Un rythme harmonique trop rapide qui désOriente l'oreille","Plus de clarté tonale","Un accompagnement plus facile à écrire"], a:1, fb:"Trop de changements d'accords créent du chaos harmonique. La mélodie contient des notes étrangères qui n'exigent pas de nouvel accord — l'ignorer surcharge l'harmonisation." },
  { q:"En G majeur, la sensible est :", opts:["F naturel","F# (Fa dièse)","G","A"], a:1, fb:"G majeur harmonique élève le VIIe degré : F naturel devient F#. F# est la sensible de G majeur — elle monte par demi-ton vers G (la tonique)." },

  // Notes étrangères (20)
  { q:"Une note de passage relie deux notes réelles :", opts:["Par un saut de tierce","Par mouvement conjoint sur un temps faible","Par un saut de quinte","Par demi-ton chromatique toujours"], a:1, fb:"La note de passage est conjointe (seconde) et généralement sur temps faible. Elle crée une liaison mélodique fluide entre deux notes réelles." },
  { q:"Une broderie se définit comme :", opts:["Une note qui quitte l'accord par saut","Une note entourée de deux notes identiques — elle part et revient sur la même note réelle","Une note qui anticipe l'accord suivant","Une note prolongée"], a:1, fb:"La broderie quitte une note réelle par un demi-ton ou un ton, puis y revient. C'est le plus simple des ornements." },
  { q:"Le retard se place sur :", opts:["Un temps faible","Un temps fort — préparé, dissonant, puis résolu","N'importe quel temps","Toujours avant la barre de mesure"], a:1, fb:"Le retard arrive sur un temps fort — c'est ce qui lui donne sa puissance. Préparé → dissonant → résolu." },
  { q:"Dans V7 → I, si F est tenu pendant l'accord de C, c'est :", opts:["Une anticipation","Un retard 4–3 — F descend vers E","Une broderie","Une note de passage"], a:1, fb:"F est la quarte qui retarde la tierce E de C. Retard classique 4→3 sur la tonique." },
  { q:"L'anticipation est :", opts:["Une note prolongée d'un accord précédent","La note de l'accord suivant introduite en avance","Une note étrangère résolue par saut","Toujours sur un temps fort"], a:1, fb:"L'anticipation joue une note de l'accord suivant avant qu'il arrive. Elle n'a pas besoin de résolution — c'est déjà la bonne note." },
  { q:"L'appoggiature diffère du retard car :", opts:["Elle n'est pas préparée — elle arrive sur un temps fort sans avoir été entendue avant","Elle est sur temps faible","Elle n'est jamais dissonante","Elle ne se résout pas"], a:0, fb:"Le retard est préparé. L'appoggiature n'est pas préparée — elle arrive brusquement sur un temps fort et se résout conjointement. Plus dramatique." },
  { q:"L'échappée se caractérise par :", opts:["Arrivée par saut, résolution conjointe","Arrivée conjointe, résolution par saut (disjoint)","Deux mouvements conjoints","Deux sauts"], a:1, fb:"L'échappée arrive conjointement puis s'échappe par un saut. Son effet de surprise vient de cette résolution inattendue." },
  { q:"Identifier les notes étrangères sert à :", opts:["Trouver des erreurs dans la mélodie","Ne pas mettre un accord sous chaque note — simplifier l'harmonisation","Transposer la mélodie","Identifier le mode"], a:1, fb:"Les notes étrangères ornent l'accord en cours sans en avoir besoin d'un propre. Les identifier évite un rythme harmonique trop rapide." },
  { q:"Dans C–D–E–D–C sur accord C majeur, D est :", opts:["Une note réelle","Note de passage (C→D→E) puis note de passage descendante (E→D→C)","Toujours une erreur","Une appoggiature"], a:1, fb:"D entre C et E = note de passage ascendante. D entre E et C = note de passage descendante. Dans les deux cas, D orne la structure C–E–C." },
  { q:"Un retard typique dans une cadence V–I est :", opts:["La quinte qui reste","La septième qui monte","La quarte qui descend vers la tierce (4–3)","La fondamentale qui saute"], a:2, fb:"Le retard 4–3 est classique sur la tonique : F (quarte) → E (tierce) sur C. Un des retards les plus fréquents de la musique tonale." },
  { q:"Parmi ces exemples, lequel est une note de passage ?", opts:["E tenu pendant C→G","D entre C et E sur accord C","G joué avant G7","B qui descend vers C sur G7→C"], a:1, fb:"D entre C et E = note de passage conjointe ascendante. Les autres sont : tenue (note réelle), anticipation, et sensible (note réelle de G7)." },
  { q:"Pourquoi les retards sont-ils sur les temps forts ?", opts:["Par convention arbitraire","Le temps fort amplifie la dissonance — la résolution est d'autant plus satisfaisante","Les temps faibles sont réservés aux accords","C'est plus facile à noter"], a:1, fb:"Sur un temps fort, la dissonance est plus perceptible. La résolution qui suit est plus satisfaisante. L'effet expressif du retard dépend de cette position métrique." },
  { q:"La mélodie C–D–E–G–E–D–C sur accord C : quelles sont les notes réelles ?", opts:["Toutes","C, E et G (la triade C) — D est note de passage","C et D seulement","G et D seulement"], a:1, fb:"C–E–G = triade C majeur. D apparaît entre C et E (NP ascendante) et entre E et C (NP descendante). D ne requiert pas de changement d'accord." },
  { q:"Dans G7, la note B pendant un accord de G7 est :", opts:["Une note étrangère","Une note réelle — B est la tierce de G7","Une broderie","Un retard"], a:1, fb:"G7 = G–B–D–F. B est la tierce de G7 — c'est une note réelle, pas étrangère." },
  { q:"L'appoggiature est souvent sur les notes :", opts:["Graves de la mélodie","Hautes de la mélodie et sur les temps forts — elle donne une accentuation expressive","Toujours chromatiques","Toujours dans l'accord"], a:1, fb:"L'appoggiature est une note expressive placée sur un temps fort — souvent sur un sommet mélodique. Son arrivée non préparée et sa résolution conjointe lui donnent son caractère pathétique." },
  { q:"Dans la mélodie E–F–G–A sur accord C majeur, F est :", opts:["Note réelle","Note de passage entre E et G","Appoggiature","Retard"], a:1, fb:"E et G sont des notes réelles de C majeur. F est entre elles — note de passage conjoncte ascendante. Pas besoin d'un nouvel accord." },
  { q:"La différence entre broderie et note de passage est :", opts:["La broderie revient sur sa note de départ ; la note de passage va vers une note différente","Elles sont identiques","La broderie est sur temps fort","La note de passage utilise des sauts"], a:0, fb:"Broderie : part d'une note et revient sur la même. Note de passage : part d'une note et continue vers une note différente. La broderie oscille ; la note de passage avance." },
  { q:"Quel ornement est préparé (entendu dans l'accord précédent) ?", opts:["L'appoggiature","L'anticipation","Le retard","L'échappée"], a:2, fb:"Le retard est la seule note étrangère préparée — elle est entendue dans l'accord précédent avant de devenir dissonante. L'appoggiature arrive sans préparation." },
  { q:"Une mélodie avec de nombreuses notes étrangères nécessite :", opts:["Beaucoup d'accords différents","Un rythme harmonique plus lent — les ornements n'exigent pas de nouveaux accords","Un tempo plus rapide","Des accords renversés uniquement"], a:1, fb:"Une mélodie ornée peut reposer sur très peu d'accords. Les notes étrangères enrichissent la ligne sans changer l'harmonie — d'où l'importance de les identifier avant d'harmoniser." },
  { q:"L'anticipation est généralement sur :", opts:["Le temps fort","Le temps faible (avant la barre ou le changement d'accord)","La dominante","Le VIe degré"], a:1, fb:"L'anticipation précède l'accord — elle est sur le temps faible juste avant le changement. Elle crée un effet de hâte légère vers la nouvelle harmonie." },

  // Squelette harmonique (25)
  { q:"Le squelette harmonique est :", opts:["La mélodie seule","L'organisation à 3–4 voix qui donne corps à la progression","La ligne de basse uniquement","L'accompagnement rythmique"], a:1, fb:"Le squelette harmonique est la réalisation à plusieurs voix de la progression — avant tout choix stylistique. Il teste la solidité de la structure harmonique." },
  { q:"La ligne de basse doit être solide aux cadences car :", opts:["Elle est toujours doublée","Les cadences parfaites exigent V et I à l'état fondamental","Elle joue toujours la quinte","La basse est toujours octavée"], a:1, fb:"La cadence parfaite (V→I) exige les deux accords à l'état fondamental. La basse joue les fondamentales — G et C — pour confirmer la résolution sans ambiguïté." },
  { q:"Les renversements à la basse servent à :", opts:["Rendre l'accord instable","Créer une ligne de basse mélodique et conjointe","Doubler la mélodie","Éviter les dissonances"], a:1, fb:"Un renversement place une tierce ou quinte à la basse — permettant des lignes de basse conjointes et mélodiques plutôt que des sauts entre fondamentales." },
  { q:"Les voix intermédiaires (alto et ténor) ont pour rôle de :", opts:["Doubler la mélodie","Compléter l'accord et assurer la continuité du tissu polyphonique","Créer des tensions","Jouer en solo"], a:1, fb:"Alto et ténor complètent l'accord — tierce, quinte, septième selon le contexte. Leur mouvement doit être fluide et préférablement conjoint." },
  { q:"Le mouvement préféré entre basse et voix supérieures est :", opts:["Parallèle","Contraire — une voix monte, l'autre descend","Oblique toujours","Toujours en tierce parallèle"], a:1, fb:"Le mouvement contraire maximise l'indépendance polyphonique et évite naturellement les parallèles. C'est le mouvement le plus équilibré." },
  { q:"La règle de doublure dans un accord à l'état fondamental est :", opts:["Doubler la tierce","Doubler la quinte","Doubler la fondamentale (sauf exceptions)","Doubler la septième"], a:2, fb:"La fondamentale est la note la plus stable — on la double par défaut. Exception : VIIe degré → doubler sa tierce (jamais la sensible)." },
  { q:"Dans I6 (premier renversement de I), la basse joue :", opts:["La fondamentale","La tierce","La quinte","La septième"], a:1, fb:"I6 = premier renversement : la tierce est à la basse. En C majeur, C/E a E (Mi) à la basse." },
  { q:"Les notes communes entre deux accords doivent :", opts:["Être évitées","Être conservées dans la même voix — elles simplifient la conduite de voix","Monter d'une seconde","Être doublées"], a:1, fb:"Conserver les notes communes réduit les déplacements. Ex : C → Am : C et E sont communes. Les garder sur place fluidifie l'écriture." },
  { q:"Quel mouvement est interdit entre toutes les voix ?", opts:["Les mouvements conjoints","Les quintes et octaves parallèles","Le mouvement contraire","Les mouvements disjoints"], a:1, fb:"Les quintes et octaves parallèles annulent l'indépendance des voix — elles donnent l'illusion que deux voix n'en font qu'une. Interdit en écriture stricte." },
  { q:"La sensible (VIIe degré) doit obligatoirement :", opts:["Descendre vers le VIe degré","Monter vers la tonique par demi-ton","Rester immobile","Sauter vers la quinte"], a:1, fb:"La sensible monte obligatoirement vers la tonique — c'est la règle absolue. En C majeur : B → C. Ce demi-ton ascendant est l'attraction mélodique fondamentale." },
  { q:"La septième de dominante (F dans G7) doit :", opts:["Monter vers G","Descendre vers E (tierce de I) par degré conjoint","Rester sur F","Sauter vers C"], a:1, fb:"La septième de dominante descend conjointement vers la tierce de l'accord suivant. F → E sur G7 → C. Règle absolue : la septième de dominante descend." },
  { q:"Quelle est la règle concernant l'espacement entre soprano et alto ?", opts:["Pas plus de deux octaves","Pas plus d'une octave","Exactement une tierce","Pas de règle"], a:1, fb:"Entre soprano et alto, et entre alto et ténor : maximum une octave. Entre ténor et basse : jusqu'à deux octaves autorisées." },
  { q:"Le principe 'moins de mouvements = meilleure écriture' signifie :", opts:["Écrire le moins de notes possible","Utiliser les notes communes et les mouvements conjoints — ne bouger que si nécessaire","Ne jamais utiliser de renversements","Toutes les voix restent immobiles"], a:1, fb:"Une bonne conduite de voix conserve les notes communes, avance par degrés conjoints et ne bouge que lorsque c'est musicalement nécessaire." },
  { q:"Dans I6/4 (deuxième renversement de I), la basse joue :", opts:["La fondamentale","La tierce","La quinte","La septième"], a:2, fb:"Le 2e renversement (6/4) place la quinte à la basse. C/G en C majeur : G (Sol) à la basse. C'est le 6/4 de cadence — il prépare la dominante." },
  { q:"La doublure de la septième est :", opts:["Obligatoire","Interdite — la septième ne se double jamais","Recommandée","Possible en mouvement contraire"], a:1, fb:"La septième ne se double jamais — elle doit résoudre conjointement vers l'accord suivant. Deux septièmes qui résoudrait vers deux notes identiques créerait des octaves parallèles." },
  { q:"Quel croisement est interdit en écriture à 4 voix ?", opts:["L'alto qui dépasse momentanément le ténor","Aucun — les voix peuvent se croiser librement","Les voix ne doivent jamais se croiser — le soprano reste toujours au-dessus de l'alto, etc.","Seule la basse peut dépasser le ténor"], a:2, fb:"Les voix ne se croisent pas : S > A > T > B en tout temps. Un croisement efface l'indépendance des voix et crée de la confusion polyphonique." },
  { q:"Un chevauchement de voix est :", opts:["Quand deux voix jouent la même note","Quand une voix dépasse la note que la voix adjacente vient de quitter","Quand les voix jouent en octave","Quand une voix saute d'une octave"], a:1, fb:"Le chevauchement : A joue une note plus haute que le S vient de quitter (ou inversement). Il crée une confusion sur l'identité des voix — interdit en écriture stricte." },
  { q:"La progression C–Am–F–G est fonctionnellement :", opts:["T–T–SD–D","T–D–SD–T","T–T–SD–T","SD–D–T–D"], a:0, fb:"C = tonique (I), Am = tonique (VI), F = sous-dominante (IV), G = dominante (V). C–Am–F–G = T–T–SD–D — une progression très courante en pop." },
  { q:"Pourquoi la basse et la mélodie ne doivent-elles pas souvent se confondre ?", opts:["Pour des raisons de registre","Car cela rigidifie le discours — on perd la richesse du dialogue entre les deux extrêmes","Car c'est interdit","Car elles jouent toujours en octaves"], a:1, fb:"Quand basse et mélodie jouent les mêmes notes, on perd la richesse du dialogue entre les registres extrêmes. Un contrechant discret de la basse est plus vivant qu'un doublement." },
  { q:"Dans la progression II–V–I, quelles notes de Dm7 se conservent dans G7 ?", opts:["Aucune","F et A — F est dans G7, A n'est pas dans G7 mais peut rester","F et C — F est dans G7 (septième) et C peut descendre vers B","D et A"], a:2, fb:"Dm7 = D–F–A–C. G7 = G–B–D–F. Notes communes : D et F. F reste comme septième de G7. D reste comme quinte de G7. A et C bougent vers G et B." },
  { q:"Une cadence parfaite exige :", opts:["Un accord renversé au moins","V et I à l'état fondamental (fondamentales à la basse)","Le VIIe degré","Un accord de sixte"], a:1, fb:"La cadence parfaite requiert V et I à l'état fondamental — les fondamentales G et C à la basse. Tout renversement la transforme en cadence imparfaite." },
  { q:"Le 6/4 de cadence (I6/4) est utilisé :", opts:["À la place de la dominante","Juste avant la dominante — il prépare V7 comme une double appoggiature","Comme tonique finale","À l'ouverture de chaque phrase"], a:1, fb:"Le 6/4 de cadence (C/G) précède G7 — ses notes G et E sont la quinte et la tierce de G7. Il agit comme une double appoggiature ascendante de la quinte et de la tierce de la dominante." },
  { q:"La tessiture du soprano en écriture SATB est :", opts:["G3 à C5","C4 à G5","C3 à G4","E2 à C4"], a:1, fb:"Soprano : C4 (Do médium) à G5. Alto : G3 à C5. Ténor : C3 à G4. Basse : E2 à C4. Ces tessitures garantissent le confort vocal et l'équilibre acoustique." },
  { q:"Qu'est-ce qu'une quinte directe (ou quinte de la battue) ?", opts:["Deux voix formant une quinte par mouvement conjoint","Deux voix extérieures (S et B) atteignant une quinte par mouvement direct (même direction)","Deux quintes consécutives","Une quinte diminuée"], a:1, fb:"La quinte directe : soprano et basse bougent dans la même direction et arrivent sur une quinte. C'est interdit entre les voix extrêmes — toléré uniquement si le soprano avance par degrés conjoints." },
  { q:"La progression I–V6–I6–IV–V7–I utilise des renversements pour :", opts:["Rendre les accords instables","Créer une ligne de basse ascendante conjointe : C–B–C–F–G–C","Éviter la dominante","Doubler la mélodie"], a:1, fb:"V6 = G/B, I6 = C/E. Basse : C→B→C→F→G→C — ligne mélodique variée et intéressante grâce aux renversements." },

  // Accompagnement (15)
  { q:"L'accompagnement est construit à partir de :", opts:["Rien — il est improvisé librement","Le squelette harmonique, dont il est la mise en forme expressive","La mélodie uniquement","Le rythme uniquement"], a:1, fb:"L'accompagnement s'appuie sur le squelette harmonique — il en est la traduction stylistique. Il soutient et amplifie la courbe de tension musicale." },
  { q:"L'arpège est caractérisé par :", opts:["Des accords plaqués simultanément","Le dépliage régulier des notes de l'accord dans le temps","Des syncopes rythmiques","Des contrepoints indépendants"], a:1, fb:"L'arpège déploie les notes de l'accord dans le temps — plutôt que simultanément. Il crée une continuité fluide caractéristique des ballades et nocturnes." },
  { q:"Le comping est issu du :", opts:["Baroque","Classique viennois","Jazz — accords ponctuels sur les contretemps avec beaucoup de silence","Romantisme"], a:2, fb:"Le comping est une technique jazz — accords courts, syncopés, avec du silence expressif. L'espace entre les accords est aussi important que les accords eux-mêmes." },
  { q:"Quel paramètre augmente la tension dans un accompagnement ?", opts:["Moins de notes","Un tempo plus lent","Plus de densité — plus de notes et rythmes plus rapides","Un ambitus serré"], a:2, fb:"La tension augmente avec la densité — plus de notes par mesure, syncopes, rythme harmonique rapide, ambitus large." },
  { q:"L'ambitus d'un accompagnement désigne :", opts:["Le nombre de voix","L'écart entre la note la plus grave et la note la plus aiguë","Le registre moyen","La durée de chaque note"], a:1, fb:"L'ambitus est l'étendue de l'accompagnement. Large = tension dramatique. Serré = compression dynamique et atmosphère intime." },
  { q:"Les notes étrangères dans l'accompagnement :", opts:["Affaiblissent l'harmonie","Créent de l'intensité — retards, appoggiatures ajoutent des dissonances expressives résolues","Doivent être évitées","N'ont aucun effet"], a:1, fb:"Les notes étrangères enrichissent l'accompagnement — un retard ou une appoggiature crée une micro-tension qui se résout, ajoutant de l'expression à chaque accord." },
  { q:"Le style basse–accord séparé est typique de :", opts:["La fugue baroque","La valse — basse sur 1, accord sur 2 et 3","Le nocturne romantique","La toccata"], a:1, fb:"La valse utilise basse(1)–accord(2)–accord(3). Ce pattern ancre le premier temps et crée le balancement caractéristique." },
  { q:"Un accompagnement en contrepoint exige :", opts:["Peu de connaissance en harmonie","La maîtrise de la conduite de voix — chaque ligne est mélodiquement autonome","Uniquement des accords plaqués","L'improvisation"], a:1, fb:"Le contrepoint traite chaque voix comme une ligne indépendante. C'est la forme la plus complexe — elle exige une maîtrise totale de la conduite de voix." },
  { q:"Un bon accompagnement ne contredit jamais :", opts:["Le tempo","La courbe de tension musicale de la mélodie","La tonalité","Le registre du chanteur"], a:1, fb:"L'accompagnement doit être cohérent avec la dynamique de tension de la mélodie — il l'annonce, l'accompagne ou la prolonge." },
  { q:"La répétition d'un motif dans l'accompagnement crée :", opts:["De la tension","De la stabilité — la répétition ancre et rassure l'oreille","De la surprise","Du désordre"], a:1, fb:"La répétition d'un motif crée de la stabilité — l'oreille reconnaît et anticipe. La variation du motif crée de la tension." },
  { q:"Un accompagnement qui 's'intensifie' peut utiliser :", opts:["Uniquement plus de tempo","Plus de notes, ambitus large, notes étrangères expressives, rythme harmonique rapide","Moins de voix","Des accords plus simples"], a:1, fb:"L'intensification combine plusieurs paramètres : densité, ambitus, rythme harmonique, notes expressives. Chacun contribue à la tension générale." },
  { q:"Quel type d'accompagnement Bach utilise-t-il dans ses chorals ?", opts:["Arpèges romantiques","Contrepoint strict à 4 voix (S, A, T, B)","Comping jazz","Accords brisés"], a:1, fb:"Les chorals de Bach sont le modèle canonique — chaque voix (soprano, alto, ténor, basse) a son propre parcours mélodique logique et chantable." },
  { q:"La mélodie 'suggère' une harmonisation quand elle :", opts:["Est très grave","Contient des arpèges d'accords ou des lignes fortement tonales","N'a pas d'armure","Est chromatique"], a:1, fb:"Une mélodie qui arpège une triade 'dessine' l'accord — la progression est évidente. Ces 'cadeaux harmoniques' rendent l'harmonisation naturelle." },
  { q:"Le mouvement conjoint dans les voix intérieures est préféré car :", opts:["Il est plus rapide à écrire","Il est plus chantable et réduit les risques de parallèles","Il sonne plus fort","Il évite les doublures"], a:1, fb:"Les mouvements conjoints sont les plus naturels vocalement. Ils minimisent les sauts risqués et réduisent les risques de quintes/octaves parallèles." },
  { q:"Les 3 étapes de l'harmonisation sont :", opts:["Mélodie / Basse / Accords","Centre tonal + notes étrangères / Squelette harmonique / Accompagnement","Accords / Rythme / Dynamique","Analyse / Écriture / Correction"], a:1, fb:"(1) Identifier le centre tonal et les notes étrangères. (2) Construire le squelette harmonique à 3–4 voix. (3) Écrire l'accompagnement expressif." },

  // Synthèse (12)
  { q:"La première étape d'une harmonisation est :", opts:["Écrire la ligne de basse","Identifier le centre tonal et le rythme harmonique","Choisir les accords","Écrire l'accompagnement"], a:1, fb:"Avant de choisir les accords, il faut identifier la tonalité et comprendre le rythme harmonique — où les accords changent, quelles notes sont réelles ou étrangères." },
  { q:"La vérification fonctionnelle d'une harmonisation s'assure que :", opts:["Tous les accords sont majeurs","Les fonctions T–SD–D–T s'enchaînent logiquement et mènent vers des cadences claires","Aucune voix ne croise","Les renversements sont évités"], a:1, fb:"Vérification fonctionnelle : les fonctions s'enchaînent (SD→D→T), les cadences sont présentes et bien marquées, la tension progresse logiquement." },
  { q:"Pourquoi dit-on qu'il n'existe pas de 'solution parfaite' en harmonisation ?", opts:["Car la théorie est incomplète","Car l'harmonisation est un art — plusieurs harmonisations peuvent être bonnes pour une même mélodie","Car les règles changent","Car la mélodie prime toujours"], a:1, fb:"L'harmonisation est créative, pas mécanique. Pour une même mélodie, plusieurs progressions peuvent être musicalement valides." },
  { q:"La démarche pour proposer des accords candidats est :", opts:["Choisir au hasard","Repérer les notes réelles, chercher les accords les contenant, vérifier la logique fonctionnelle","Toujours I–IV–V–I","Toujours commencer par la dominante"], a:1, fb:"(1) Identifier les notes réelles. (2) Lister les accords diatoniques les contenant. (3) Vérifier T–SD–D–T. (4) Choisir l'accord le plus naturel." },
  { q:"La progression Am–Dm–G7–C est fonctionnellement :", opts:["T–T–D–T","T–SD–D–T","SD–D–T–T","D–T–SD–T"], a:1, fb:"Am = tonique (VI), Dm = sous-dominante (II), G7 = dominante (V), C = tonique (I). T–SD–D–T — le cycle fonctionnel fondamental." },
  { q:"Dans C/G (2e renversement), la basse joue :", opts:["C","E","G","B"], a:2, fb:"C/G = accord de C majeur avec G à la basse. 2e renversement : la quinte est à la basse." },
  { q:"Quel accord de C majeur contient le triton F–B ?", opts:["C","F","G7","Am"], a:2, fb:"G7 = G–B–D–F. Il contient B et F — le triton fonctionnel de C. C'est la dominante qui pousse vers C." },
  { q:"Si la mélodie contient C# dans une tonalité à 0 dièse, c'est probablement :", opts:["Une erreur","Une tonicisation de D ou un emprunt — C# est la sensible de D","Une note de broderie","La fondamentale d'un accord"], a:1, fb:"En C majeur, C# est hors gamme. C'est probablement la sensible de D (V/V) — tonicisation ou emprunt. La présence de D qui suit confirme." },
  { q:"Pour harmoniser E–F–G–A sur accord G majeur, F est :", opts:["Note réelle","Note de passage entre E et G — E et G sont dans G, F les relie","Appoggiature","Retard"], a:1, fb:"G majeur : G–B–D. Mais dans ce contexte avec E et G comme notes réelles (E = 6e, G = fondamentale), F est note de passage conjoncte entre E et G." },
  { q:"La note A dans la mélodie, pendant l'accord de F (Fa majeur), est :", opts:["Une note étrangère","Une note réelle — A est la tierce de F","Une broderie","Un retard"], a:1, fb:"F majeur = F–A–C. A est la tierce de F — c'est une note réelle de l'accord. Pas une note étrangère." },
  { q:"La progression I–IV–V7–I en C est :", opts:["C–F–G7–C","C–G–F–C","C–Dm–G7–C","C–Am–G7–C"], a:0, fb:"I = C, IV = F, V7 = G7, I = C. La progression fondamentale T–SD–D–T en C majeur : C–F–G7–C." },
  { q:"Un accompagnement de type 'arpège' convient particulièrement à :", opts:["Une fugue baroque à tempo vif","Une ballade lyrique ou un nocturne — il crée fluidité et continuité","Un standard de jazz moderne","Une fanfare militaire"], a:1, fb:"L'arpège est le style d'accompagnement des ballades et nocturnes — Chopin, Schubert, Brahms. Sa continuité fluide soutient les mélodies longues et chantantes." },
];

// English translations — add when available; until then falls back to fr


const questionsEn: Question[] = [{ q:"What is the first thing to analyze in order to identify the tonal center?", opts:["The tempo","The key signature","The length","The register"], a:1, fb:"The key signature immediately indicates the probable keys — the major scale and its relative minor. It is the first landmark in tonal analysis." },
{ q:"2 sharps (F# and C#) correspond to the key of:", opts:["G major or E minor","D major or B minor","A major or F# minor","B♭ major or G minor"], a:1, fb:"2 sharps = key signature of D major / B minor. F# and C# are the constituent accidentals of both scales." },
{ q:"The leading tone is recognized by:", opts:["A leap of a third","A half-step ascending toward a stable note","A long sustained note","A leap of a fifth"], a:1, fb:"The leading tone is the harmonic 7th degree — it rises a half-step to the tonic. It is the strongest melodic attraction in the scale." },
{ q:"A sustained note on a strong beat at the beginning of a phrase often corresponds to:", opts:["The dominant","The 7th degree","The 1st or 6th degree — poles of stability","A non-chord tone"], a:2, fb:"Stable notes on strong beats correspond to degrees I and VI — the tonic poles. The melody naturally rests on them." },
{ q:"A prolonged accidental lasting several measures indicates:", opts:["A momentary borrowing","A possible modulation","A notation error","A suspension"], a:1, fb:"A brief accidental = borrowing. Prolonged = the tonal center may have shifted — a sign of modulation to a new key." },
{ q:"The final cadence is useful for identifying the tonal center because:", opts:["It is always V7–I","It reveals the actual resolution — the local degree I","It uses whole notes","It is always in major"], a:1, fb:"The final cadence shows how the phrase resolves. The degree I of the cadence is the local tonal center." },
{ q:"Harmonic rhythm is:", opts:["The metronome speed","The frequency of chord changes","The number of notes per measure","The type of meter"], a:1, fb:"Harmonic rhythm is the frequency at which chords change — independent of tempo." },
{ q:"Why do not all the notes of a melody necessarily correspond to the chord?", opts:["Because the melody may be wrong","Because some are non-chord tones — ornaments that do not belong to the chord","Because the chord is always inverted","Because accidentals change everything"], a:1, fb:"The melody often contains non-chord tones. Identifying them avoids stacking unnecessary chords." },
{ q:"'Chord tones' are:", opts:["Notes played in octaves","Notes that belong to the current harmonic chord","Notes without accidentals","Bass notes"], a:1, fb:"Chord tones belong to the chord — they constitute the harmonic structure. The others ornament that structure." },
{ q:"A borrowing differs from a modulation because:", opts:["Borrowing uses inverted chords","Borrowing is momentary and does not shift the tonal center","Borrowing always follows V7–I","Borrowing uses the Neapolitan"], a:1, fb:"A borrowing is brief. A modulation durably establishes a new key — confirmed by a perfect cadence in the new center." },
{ q:"The key of F major has how many flats?", opts:["None","One (B♭)","Two (B♭, E♭)","Three"], a:1, fb:"F major has one flat: B♭. It is the one-flat key signature — the scale F G A B♭ C D E F." },
{ q:"A melody that revolves around G and rises toward A♭ suggests:", opts:["C major","A♭ major or F minor","G major","D minor"], a:1, fb:"G → A♭ is an ascending half-step: G acts as the leading tone of A♭. The key is probably A♭ major or F minor (relative)." },
{ q:"A minor key is distinguished from its parallel major in the melody by:", opts:["Its key signature alone","The recurring presence of the minor 3rd degree and the specific leading tone","Its tempo","Its register"], a:1, fb:"In minor, the melody gravitates around the minor third (Eb in C minor) and the harmonic leading tone (B natural). These notes characterize the minor mode even without a key signature." },
{ q:"Which melody suggests C major rather than A minor?", opts:["A melody that ends on A","A melody that begins and ends on C, with frequent emphasis on E and G","A melody with many low notes","A melody in triplets"], a:1, fb:"If the melody is anchored on C (tonic), E (third), and G (fifth) and ends on C, the key is C major. If it is anchored on A, it is A minor." },
{ q:"The harmonic rhythm of a ballad is typically:", opts:["One chord per note","One chord per measure or half-measure","One chord per eighth note","No regular chords"], a:1, fb:"A ballad changes chords slowly — often once per measure. Each chord has time to settle in the ear." },
{ q:"Tonicization is recognized in the melody by:", opts:["A long sustained note","An artificial leading tone — a half-step ascending toward a non-tonic degree","A leap of a fifth","A suspension"], a:1, fb:"A tonicization creates a temporary leading tone toward a non-tonic chord. E.g.: C# (leading tone of D) followed by D in a melody in G major = tonicization of Dm." },
{ q:"If the melody contains an F# in a key with 0 sharps, it is probably:", opts:["An error","A tonicization of G (of which F# is the leading tone) or a borrowing","A neighbor tone","The root of a chord"], a:1, fb:"In C major, F# is outside the scale. It is probably the leading tone of G (V), creating a tonicization V/V — or a borrowing. The presence of G that follows confirms the tonicization." },
{ q:"What differentiates 'stable points' from passing tones in a melody?", opts:["Their pitch","Stable points are on strong beats and degrees I/VI — passing tones connect stable notes","Their duration alone","Their register"], a:1, fb:"Stable points: strong beats, long durations, degrees I and VI. Passing tones: weak beats, short durations, connecting two chord tones. Metric position is a key indicator." },
{ q:"Harmonizing every note with a different chord creates:", opts:["A rich and beautiful harmony","A harmonic rhythm that is too fast and disorients the ear","More tonal clarity","An easier accompaniment to write"], a:1, fb:"Too many chord changes create harmonic chaos. The melody contains non-chord tones that do not require a new chord — ignoring this overburdens the harmonization." },
{ q:"In G major, the leading tone is:", opts:["F natural","F# (F sharp)","G","A"], a:1, fb:"Harmonic G major raises the 7th degree: F natural becomes F#. F# is the leading tone of G major — it rises a half-step to G (the tonic)." },

{ q:"A passing tone connects two chord tones:", opts:["By a leap of a third","By stepwise motion on a weak beat","By a leap of a fifth","Always by a chromatic half-step"], a:1, fb:"The passing tone moves by step (a second) and is generally on a weak beat. It creates a smooth melodic link between two chord tones." },
{ q:"A neighbor tone is defined as:", opts:["A note that leaves the chord by leap","A note surrounded by two identical notes — it departs from and returns to the same chord tone","A note that anticipates the next chord","A sustained note"], a:1, fb:"The neighbor tone leaves a chord tone by a half-step or whole step, then returns to it. It is the simplest of ornaments." },
{ q:"A suspension falls on:", opts:["A weak beat","A strong beat — prepared, dissonant, then resolved","Any beat","Always before the barline"], a:1, fb:"The suspension arrives on a strong beat — that is what gives it its power. Prepared → dissonant → resolved." },
{ q:"In V7 → I, if F is held over the chord of C, it is:", opts:["An anticipation","A 4–3 suspension — F descends to E","A neighbor tone","A passing tone"], a:1, fb:"F is the fourth that delays the third E of C. Classic 4→3 suspension on the tonic." },
{ q:"An anticipation is:", opts:["A note held over from a previous chord","The note of the next chord introduced early","A non-chord tone resolved by leap","Always on a strong beat"], a:1, fb:"The anticipation plays a note of the next chord before it arrives. It needs no resolution — it is already the correct note." },
{ q:"The appoggiatura differs from the suspension because:", opts:["It is not prepared — it arrives on a strong beat without having been heard before","It is on a weak beat","It is never dissonant","It does not resolve"], a:0, fb:"The suspension is prepared. The appoggiatura is not prepared — it arrives abruptly on a strong beat and resolves by step. More dramatic." },
{ q:"The escape tone is characterized by:", opts:["Arrival by leap, resolution by step","Arrival by step, resolution by leap (disjunct)","Two stepwise motions","Two leaps"], a:1, fb:"The escape tone arrives by step then escapes by a leap. Its surprising effect comes from this unexpected resolution." },
{ q:"Identifying non-chord tones serves to:", opts:["Find errors in the melody","Avoid placing a chord under every note — simplifying the harmonization","Transpose the melody","Identify the mode"], a:1, fb:"Non-chord tones ornament the current chord without requiring one of their own. Identifying them avoids a harmonic rhythm that is too fast." },
{ q:"In C–D–E–D–C over a C major chord, D is:", opts:["A chord tone","A passing tone (C→D→E) then a descending passing tone (E→D→C)","Always an error","An appoggiatura"], a:1, fb:"D between C and E = ascending passing tone. D between E and C = descending passing tone. In both cases, D ornaments the structure C–E–C." },
{ q:"A typical suspension in a V–I cadence is:", opts:["The fifth that remains","The seventh that rises","The fourth that descends to the third (4–3)","The root that leaps"], a:2, fb:"The 4–3 suspension is classic on the tonic: F (fourth) → E (third) over C. One of the most frequent suspensions in tonal music." },
{ q:"Among these examples, which is a passing tone?", opts:["E sustained during C→G","D between C and E over a C chord","G played before G7","B descending to C over G7→C"], a:1, fb:"D between C and E = ascending conjunct passing tone. The others are: a sustained note (chord tone), an anticipation, and a leading tone (chord tone of G7)." },
{ q:"Why are suspensions on strong beats?", opts:["By arbitrary convention","The strong beat amplifies the dissonance — the resolution is all the more satisfying","Weak beats are reserved for chords","It is easier to notate"], a:1, fb:"On a strong beat, the dissonance is more perceptible. The resolution that follows is more satisfying. The expressive effect of the suspension depends on this metric position." },
{ q:"The melody C–D–E–G–E–D–C over a C chord: which are the chord tones?", opts:["All of them","C, E, and G (the C triad) — D is a passing tone","C and D only","G and D only"], a:1, fb:"C–E–G = C major triad. D appears between C and E (ascending PT) and between E and C (descending PT). D does not require a chord change." },
{ q:"In G7, the note B during a G7 chord is:", opts:["A non-chord tone","A chord tone — B is the third of G7","A neighbor tone","A suspension"], a:1, fb:"G7 = G–B–D–F. B is the third of G7 — it is a chord tone, not a non-chord tone." },
{ q:"The appoggiatura is often on:", opts:["Low notes of the melody","High notes of the melody and on strong beats — it gives expressive accentuation","Always chromatic notes","Always chord tones"], a:1, fb:"The appoggiatura is an expressive note placed on a strong beat — often on a melodic peak. Its unprepared arrival and stepwise resolution give it its pathetic character." },
{ q:"In the melody E–F–G–A over a C major chord, F is:", opts:["A chord tone","A passing tone between E and G","An appoggiatura","A suspension"], a:1, fb:"E and G are chord tones of C major. F is between them — ascending conjunct passing tone. No new chord is needed." },
{ q:"The difference between a neighbor tone and a passing tone is:", opts:["The neighbor tone returns to its starting note; the passing tone moves toward a different note","They are identical","The neighbor tone is on a strong beat","The passing tone uses leaps"], a:0, fb:"Neighbor tone: leaves a note and returns to the same one. Passing tone: leaves a note and continues to a different note. The neighbor tone oscillates; the passing tone moves forward." },
{ q:"Which ornament is prepared (heard in the previous chord)?", opts:["The appoggiatura","The anticipation","The suspension","The escape tone"], a:2, fb:"The suspension is the only prepared non-chord tone — it is heard in the previous chord before becoming dissonant. The appoggiatura arrives without preparation." },
{ q:"A melody with many non-chord tones requires:", opts:["Many different chords","A slower harmonic rhythm — the ornaments do not require new chords","A faster tempo","Inverted chords only"], a:1, fb:"An ornamented melody can rest on very few chords. Non-chord tones enrich the line without changing the harmony — hence the importance of identifying them before harmonizing." },
{ q:"The anticipation is generally on:", opts:["The strong beat","The weak beat (before the barline or chord change)","The dominant","The 6th degree"], a:1, fb:"The anticipation precedes the chord — it is on the weak beat just before the change. It creates a slight sense of hurrying toward the new harmony." },

{ q:"The harmonic skeleton is:", opts:["The melody alone","The 3–4 voice framework that gives body to the progression","The bass line only","The rhythmic accompaniment"], a:1, fb:"The harmonic skeleton is the multi-voice realization of the progression — before any stylistic choices. It tests the solidity of the harmonic structure." },
{ q:"The bass line must be solid at cadences because:", opts:["It is always doubled","Perfect cadences require V and I in root position","It always plays the fifth","The bass is always octaved"], a:1, fb:"The perfect cadence (V→I) requires both chords in root position. The bass plays the roots — G and C — to confirm the resolution unambiguously." },
{ q:"Bass inversions serve to:", opts:["Make the chord unstable","Create a melodic and stepwise bass line","Double the melody","Avoid dissonances"], a:1, fb:"An inversion places a third or fifth in the bass — allowing stepwise and melodic bass lines rather than leaps between roots." },
{ q:"The inner voices (alto and tenor) have the role of:", opts:["Doubling the melody","Completing the chord and ensuring the continuity of the polyphonic texture","Creating tensions","Playing as a solo"], a:1, fb:"Alto and tenor complete the chord — third, fifth, seventh depending on context. Their movement should be smooth and preferably stepwise." },
{ q:"The preferred motion between the bass and upper voices is:", opts:["Parallel","Contrary — one voice rises, the other descends","Always oblique","Always in parallel thirds"], a:1, fb:"Contrary motion maximizes polyphonic independence and naturally avoids parallels. It is the most balanced motion." },
{ q:"The doubling rule in a root-position chord is:", opts:["Double the third","Double the fifth","Double the root (with exceptions)","Double the seventh"], a:2, fb:"The root is the most stable note — it is doubled by default. Exception: 7th degree → double its third (never the leading tone)." },
{ q:"In I6 (first inversion of I), the bass plays:", opts:["The root","The third","The fifth","The seventh"], a:1, fb:"I6 = first inversion: the third is in the bass. In C major, C/E has E in the bass." },
{ q:"Common tones between two chords should:", opts:["Be avoided","Be kept in the same voice — they simplify voice leading","Move up a second","Be doubled"], a:1, fb:"Keeping common tones reduces movement. E.g.: C → Am: C and E are common. Holding them in place smooths the writing." },
{ q:"Which motion is forbidden between all voices?", opts:["Stepwise motion","Parallel fifths and octaves","Contrary motion","Disjunct motion"], a:1, fb:"Parallel fifths and octaves eliminate the independence of the voices — they give the illusion that two voices are one. Forbidden in strict writing." },
{ q:"The leading tone (7th degree) must obligatorily:", opts:["Descend to the 6th degree","Rise to the tonic by half-step","Remain stationary","Leap to the fifth"], a:1, fb:"The leading tone must rise to the tonic — this is the absolute rule. In C major: B → C. This ascending half-step is the fundamental melodic attraction." },
{ q:"The dominant seventh (F in G7) must:", opts:["Rise to G","Descend to E (third of I) by step","Stay on F","Leap to C"], a:1, fb:"The dominant seventh descends by step to the third of the following chord. F → E on G7 → C. Absolute rule: the dominant seventh descends." },
{ q:"What is the rule regarding the spacing between soprano and alto?", opts:["No more than two octaves","No more than one octave","Exactly a third","No rule"], a:1, fb:"Between soprano and alto, and between alto and tenor: maximum one octave. Between tenor and bass: up to two octaves is permitted." },
{ q:"The principle 'less motion = better writing' means:", opts:["Write as few notes as possible","Use common tones and stepwise motion — move only when necessary","Never use inversions","All voices remain stationary"], a:1, fb:"Good voice leading keeps common tones, moves by step, and moves only when musically necessary." },
{ q:"In I6/4 (second inversion of I), the bass plays:", opts:["The root","The third","The fifth","The seventh"], a:2, fb:"The 2nd inversion (6/4) places the fifth in the bass. C/G in C major: G in the bass. This is the cadential 6/4 — it prepares the dominant." },
{ q:"Doubling the seventh is:", opts:["Obligatory","Forbidden — the seventh is never doubled","Recommended","Possible in contrary motion"], a:1, fb:"The seventh is never doubled — it must resolve by step to the next chord. Two sevenths resolving to two identical notes would create parallel octaves." },
{ q:"Which crossing is forbidden in four-voice writing?", opts:["The alto momentarily exceeding the tenor","None — voices may cross freely","Voices must never cross — the soprano always remains above the alto, etc.","Only the bass may exceed the tenor"], a:2, fb:"Voices do not cross: S > A > T > B at all times. A crossing erases the independence of the voices and creates polyphonic confusion." },
{ q:"A voice overlap is:", opts:["When two voices play the same note","When a voice exceeds the note that the adjacent voice has just left","When voices play in octaves","When a voice leaps an octave"], a:1, fb:"Overlap: A plays a note higher than what S just left (or vice versa). It creates confusion about the identity of the voices — forbidden in strict writing." },
{ q:"The progression C–Am–F–G is functionally:", opts:["T–T–SD–D","T–D–SD–T","T–T–SD–T","SD–D–T–D"], a:0, fb:"C = tonic (I), Am = tonic (VI), F = subdominant (IV), G = dominant (V). C–Am–F–G = T–T–SD–D — a very common progression in pop music." },
{ q:"Why should the bass and melody not often coincide?", opts:["For reasons of register","Because it rigidifies the discourse — we lose the richness of the dialogue between the two extremes","Because it is forbidden","Because they always play in octaves"], a:1, fb:"When bass and melody play the same notes, we lose the richness of the dialogue between the extreme registers. A subtle countermelody in the bass is more alive than a doubling." },
{ q:"In the progression II–V–I, which notes of Dm7 are kept in G7?", opts:["None","F and A — F is in G7, A is not in G7 but may remain","F and C — F is in G7 (seventh) and C can descend to B","D and A"], a:2, fb:"Dm7 = D–F–A–C. G7 = G–B–D–F. Common tones: D and F. F remains as the seventh of G7. D remains as the fifth of G7. A and C move to G and B." },
{ q:"A perfect cadence requires:", opts:["At least one inverted chord","V and I in root position (roots in the bass)","The 7th degree","A sixth chord"], a:1, fb:"The perfect cadence requires V and I in root position — the roots G and C in the bass. Any inversion transforms it into an imperfect cadence." },
{ q:"The cadential 6/4 (I6/4) is used:", opts:["In place of the dominant","Just before the dominant — it prepares V7 as a double appoggiatura","As the final tonic","At the opening of each phrase"], a:1, fb:"The cadential 6/4 (C/G) precedes G7 — its notes G and E are the fifth and third of G7. It acts as a double appoggiatura of the fifth and third of the dominant." },
{ q:"The soprano range in SATB writing is:", opts:["G3 to C5","C4 to G5","C3 to G4","E2 to C4"], a:1, fb:"Soprano: C4 to G5. Alto: G3 to C5. Tenor: C3 to G4. Bass: E2 to C4. These ranges ensure vocal comfort and acoustic balance." },
{ q:"What is a direct fifth (or horn fifth)?", opts:["Two voices forming a fifth by stepwise motion","Two outer voices (S and B) reaching a fifth by direct motion (same direction)","Two consecutive fifths","A diminished fifth"], a:1, fb:"The direct fifth: soprano and bass move in the same direction and arrive on a fifth. Forbidden between the outer voices — tolerated only if the soprano moves by step." },
{ q:"The progression I–V6–I6–IV–V7–I uses inversions to:", opts:["Make the chords unstable","Create an ascending stepwise bass line: C–B–C–F–G–C","Avoid the dominant","Double the melody"], a:1, fb:"V6 = G/B, I6 = C/E. Bass: C→B→C→F→G→C — a varied and interesting melodic line made possible by the inversions." },

{ q:"The accompaniment is built from:", opts:["Nothing — it is freely improvised","The harmonic skeleton, of which it is the expressive realization","The melody alone","The rhythm alone"], a:1, fb:"The accompaniment is based on the harmonic skeleton — it is its stylistic translation. It supports and amplifies the musical curve of tension." },
{ q:"An arpeggio is characterized by:", opts:["Simultaneously struck block chords","The regular unfolding of the chord tones in time","Rhythmic syncopations","Independent counterpoint lines"], a:1, fb:"The arpeggio unfolds the chord tones in time — rather than simultaneously. It creates a fluid continuity characteristic of ballads and nocturnes." },
{ q:"Comping originates from:", opts:["The Baroque","The Viennese Classical period","Jazz — punctual chords on off-beats with much silence","Romanticism"], a:2, fb:"Comping is a jazz technique — short, syncopated chords, with expressive silence. The space between the chords is as important as the chords themselves." },
{ q:"Which parameter increases tension in an accompaniment?", opts:["Fewer notes","A slower tempo","More density — more notes and faster rhythms","A narrow range"], a:2, fb:"Tension increases with density — more notes per measure, syncopations, faster harmonic rhythm, wide range." },
{ q:"The range of an accompaniment refers to:", opts:["The number of voices","The distance between the lowest and highest note","The average register","The duration of each note"], a:1, fb:"Range is the span of the accompaniment. Wide = dramatic tension. Narrow = dynamic compression and intimate atmosphere." },
{ q:"Non-chord tones in the accompaniment:", opts:["Weaken the harmony","Create intensity — suspensions, appoggiaturas add expressive dissonances that resolve","Should be avoided","Have no effect"], a:1, fb:"Non-chord tones enrich the accompaniment — a suspension or appoggiatura creates a micro-tension that resolves, adding expression to each chord." },
{ q:"The separate bass–chord style is typical of:", opts:["Baroque fugue","The waltz — bass on beat 1, chord on beats 2 and 3","The Romantic nocturne","The toccata"], a:1, fb:"The waltz uses bass(1)–chord(2)–chord(3). This pattern anchors the first beat and creates the characteristic swaying feel." },
{ q:"A contrapuntal accompaniment requires:", opts:["Little knowledge of harmony","Mastery of voice leading — each line is melodically autonomous","Only block chords","Improvisation"], a:1, fb:"Counterpoint treats each voice as an independent line. It is the most complex form — it requires complete mastery of voice leading." },
{ q:"A good accompaniment never contradicts:", opts:["The tempo","The musical tension curve of the melody","The key","The singer's register"], a:1, fb:"The accompaniment must be consistent with the tension dynamics of the melody — it announces, accompanies, or prolongs it." },
{ q:"The repetition of a motif in the accompaniment creates:", opts:["Tension","Stability — repetition anchors and reassures the ear","Surprise","Disorder"], a:1, fb:"Repetition of a motif creates stability — the ear recognizes and anticipates. Variation of the motif creates tension." },
{ q:"An accompaniment that 'intensifies' can use:", opts:["Only a faster tempo","More notes, wide range, expressive non-chord tones, faster harmonic rhythm","Fewer voices","Simpler chords"], a:1, fb:"Intensification combines several parameters: density, range, harmonic rhythm, expressive notes. Each contributes to the overall tension." },
{ q:"What type of accompaniment does Bach use in his chorales?", opts:["Romantic arpeggios","Strict four-voice counterpoint (S, A, T, B)","Jazz comping","Broken chords"], a:1, fb:"Bach's chorales are the canonical model — each voice (soprano, alto, tenor, bass) has its own logical and singable melodic path." },
{ q:"A melody 'suggests' a harmonization when it:", opts:["Is very low","Contains chord arpeggios or strongly tonal lines","Has no key signature","Is chromatic"], a:1, fb:"A melody that arpeggios a triad 'draws' the chord — the progression is obvious. These 'harmonic gifts' make the harmonization natural." },
{ q:"Stepwise motion in the inner voices is preferred because:", opts:["It is faster to write","It is more singable and reduces the risk of parallels","It sounds louder","It avoids doublings"], a:1, fb:"Stepwise motions are the most natural vocally. They minimize risky leaps and reduce the risk of parallel fifths/octaves." },
{ q:"The 3 steps of harmonization are:", opts:["Melody / Bass / Chords","Tonal center + non-chord tones / Harmonic skeleton / Accompaniment","Chords / Rhythm / Dynamics","Analysis / Writing / Correction"], a:1, fb:"(1) Identify the tonal center and non-chord tones. (2) Build the 3–4 voice harmonic skeleton. (3) Write the expressive accompaniment." },

{ q:"The first step of a harmonization is:", opts:["Write the bass line","Identify the tonal center and harmonic rhythm","Choose the chords","Write the accompaniment"], a:1, fb:"Before choosing chords, you must identify the key and understand the harmonic rhythm — where chords change, which notes are chord tones or non-chord tones." },
{ q:"The functional verification of a harmonization ensures that:", opts:["All chords are major","The functions T–SD–D–T flow logically and lead to clear cadences","No voice crosses","Inversions are avoided"], a:1, fb:"Functional verification: functions flow in sequence (SD→D→T), cadences are present and well-marked, tension progresses logically." },
{ q:"Why is it said that there is no 'perfect solution' in harmonization?", opts:["Because the theory is incomplete","Because harmonization is an art — several harmonizations can be valid for the same melody","Because the rules change","Because the melody always takes precedence"], a:1, fb:"Harmonization is creative, not mechanical. For the same melody, several progressions can be musically valid." },
{ q:"The approach for proposing candidate chords is:", opts:["Choose randomly","Identify the chord tones, find the chords containing them, verify functional logic","Always I–IV–V–I","Always start with the dominant"], a:1, fb:"(1) Identify the chord tones. (2) List the diatonic chords containing them. (3) Verify T–SD–D–T. (4) Choose the most natural chord." },
{ q:"The progression Am–Dm–G7–C is functionally:", opts:["T–T–D–T","T–SD–D–T","SD–D–T–T","D–T–SD–T"], a:1, fb:"Am = tonic (VI), Dm = subdominant (II), G7 = dominant (V), C = tonic (I). T–SD–D–T — the fundamental functional cycle." },
{ q:"In C/G (2nd inversion), the bass plays:", opts:["C","E","G","B"], a:2, fb:"C/G = C major chord with G in the bass. 2nd inversion: the fifth is in the bass." },
{ q:"Which chord in C major contains the tritone F–B?", opts:["C","F","G7","Am"], a:2, fb:"G7 = G–B–D–F. It contains B and F — the functional tritone of C. It is the dominant that pushes toward C." },
{ q:"If the melody contains C# in a key with 0 sharps, it is probably:", opts:["An error","A tonicization of D or a borrowing — C# is the leading tone of D","A neighbor tone","The root of a chord"], a:1, fb:"In C major, C# is outside the scale. It is probably the leading tone of D (V/V) — tonicization or borrowing. The presence of D that follows confirms it." },
{ q:"To harmonize E–F–G–A over a G major chord, F is:", opts:["A chord tone","A passing tone between E and G — E and G are in G, F connects them","An appoggiatura","A suspension"], a:1, fb:"G major: G–B–D. But in this context with E and G as chord tones (E = 6th, G = root), F is a conjunct passing tone between E and G." },
{ q:"The note A in the melody, during the chord of F (F major), is:", opts:["A non-chord tone","A chord tone — A is the third of F","A neighbor tone","A suspension"], a:1, fb:"F major = F–A–C. A is the third of F — it is a chord tone of the chord. Not a non-chord tone." },
{ q:"The progression I–IV–V7–I in C is:", opts:["C–F–G7–C","C–G–F–C","C–Dm–G7–C","C–Am–G7–C"], a:0, fb:"I = C, IV = F, V7 = G7, I = C. The fundamental T–SD–D–T progression in C major: C–F–G7–C." },
{ q:"An arpeggio-style accompaniment is particularly suited to:", opts:["A fast-tempo Baroque fugue","A lyrical ballad or nocturne — it creates fluidity and continuity","A modern jazz standard","A military fanfare"], a:1, fb:"The arpeggio is the accompaniment style of ballads and nocturnes — Chopin, Schubert, Brahms. Its fluid continuity supports long, lyrical melodies and creates a gentle, flowing texture." },
];

const questionsEs: Question[] = [{ q:"¿Cuál es lo primero que hay que analizar para identificar el centro tonal?", opts:["El tempo","La armadura","La duración","El registro"], a:1, fb:"La armadura indica inmediatamente las tonalidades probables — la escala mayor y su relativa menor. Es el primer punto de referencia del análisis tonal." },
{ q:"2 sostenidos (F# y C#) corresponden a la tonalidad de:", opts:["G mayor o E menor","D mayor o B menor","A mayor o F# menor","B♭ mayor o G menor"], a:1, fb:"2 sostenidos = armadura de D mayor / B menor. F# y C# son las alteraciones constitutivas de estas dos escalas." },
{ q:"La sensible se reconoce por:", opts:["Un salto de tercera","Un semitono ascendente hacia una nota estable","Una larga nota tenida","Un salto de quinta"], a:1, fb:"La sensible es el VII grado armónico — sube un semitono hacia la tónica. Es la atracción melódica más fuerte de la escala." },
{ q:"Una nota tenida en un tiempo fuerte al comienzo de una frase corresponde frecuentemente a:", opts:["La dominante","El VII grado","El I o VI grado — polos de estabilidad","Una nota extraña"], a:2, fb:"Las notas estables en los tiempos fuertes corresponden a los grados I y VI — los polos tónicos. La melodía reposa en ellos de manera natural." },
{ q:"Una alteración accidental prolongada durante varios compases indica:", opts:["Un préstamo puntual","Una posible modulación","Un error de notación","Un retardo"], a:1, fb:"Alteración puntual = préstamo. Prolongada = el centro tonal puede haber cambiado — señal de una modulación hacia una nueva tonalidad." },
{ q:"La cadencia final es útil para identificar el centro tonal porque:", opts:["Siempre es V7–I","Revela la resolución real — el grado I local","Usa redondas","Siempre está en mayor"], a:1, fb:"La cadencia final muestra cómo se resuelve la frase. El grado I de la cadencia es el centro tonal local." },
{ q:"El ritmo armónico es:", opts:["La velocidad del metrónomo","La frecuencia de cambio de los acordes","El número de notas por compás","El tipo de compás"], a:1, fb:"El ritmo armónico es la frecuencia con la que cambian los acordes — independientemente del tempo." },
{ q:"¿Por qué no todas las notas de una melodía corresponden necesariamente al acorde?", opts:["Porque la melodía puede estar equivocada","Porque algunas son notas extrañas — adornos que no forman parte del acorde","Porque el acorde siempre está invertido","Porque las alteraciones lo cambian todo"], a:1, fb:"La melodía contiene frecuentemente notas extrañas. Identificarlas evita apilar acordes innecesarios." },
{ q:"Las 'notas reales' son:", opts:["Las notas tocadas en doble","Las notas que pertenecen al acorde armónico en curso","Las notas sin alteración","Las notas del bajo"], a:1, fb:"Las notas reales pertenecen al acorde — constituyen la estructura armónica. Las demás adornan esa estructura." },
{ q:"Un préstamo difiere de una modulación porque:", opts:["El préstamo utiliza acordes invertidos","El préstamo es momentáneo y no desplaza el centro tonal","El préstamo siempre sigue V7–I","El préstamo utiliza el napolitano"], a:1, fb:"Un préstamo es breve. Una modulación instala de manera duradera una nueva tonalidad — confirmada por una cadencia perfecta en el nuevo centro." },
{ q:"La tonalidad de F mayor tiene cuántos bemoles:", opts:["Ninguno","Uno (B♭)","Dos (B♭, E♭)","Tres"], a:1, fb:"F mayor tiene un bemol: Si♭ (B♭). Es la armadura de un bemol — la escala F G A B♭ C D E F." },
{ q:"La melodía que gira en torno a G y sube hacia A♭ sugiere:", opts:["C mayor","A♭ mayor o F menor","G mayor","D menor"], a:1, fb:"G → A♭ es un semitono ascendente: G actúa como sensible de A♭. La tonalidad es probablemente A♭ mayor o F menor (relativa)." },
{ q:"Una tonalidad menor se distingue de su homónima mayor en la melodía por:", opts:["Su armadura únicamente","La presencia recurrente del III grado menor y de la sensible específica","Su tempo","Su registro"], a:1, fb:"En menor, la melodía gravita en torno a la tercera menor (Eb en C menor) y a la sensible armónica (B natural). Estas notas caracterizan el modo menor incluso sin armadura." },
{ q:"¿Qué melodía sugiere C mayor en lugar de A menor?", opts:["Una melodía que termina en A","Una melodía que comienza y termina en C, con apoyos frecuentes en E y G","Una melodía con muchas notas graves","Una melodía en tresillos"], a:1, fb:"Si la melodía se ancla en C (tónica), E (tercera) y G (quinta) y termina en C, la tonalidad es C mayor. Si se ancla en A, es A menor." },
{ q:"El ritmo armónico de una balada es típicamente:", opts:["Un acorde por nota","Un acorde por compás o medio compás","Un acorde por corchea","Ningún acorde regular"], a:1, fb:"Una balada cambia de acorde lentamente — a menudo una vez por compás. Cada acorde tiene tiempo de instalarse en el oído." },
{ q:"La tonicización se reconoce en la melodía por:", opts:["Una larga nota tenida","Una sensible artificial — semitono ascendente hacia un grado no tónico","Un salto de quinta","Un retardo"], a:1, fb:"Una tonicización crea una sensible temporal hacia un acorde no tónico. Ej.: C# (sensible de D) seguido de D en una melodía en G mayor = tonicización de Dm." },
{ q:"Si la melodía contiene un F# en una tonalidad con 0 sostenidos, probablemente es:", opts:["Un error","Una tonicización de G (cuya sensible es F#) o un préstamo","Una nota de bordado","La fundamental de un acorde"], a:1, fb:"En C mayor, F# está fuera de la escala. Es probablemente la sensible de G (V), creando una tonicización V/V — o un préstamo. La presencia de G a continuación confirma la tonicización." },
{ q:"¿Qué diferencia los 'puntos estables' de las notas de paso en una melodía?", opts:["Su altura","Los puntos estables están en los tiempos fuertes y en los grados I/VI — las notas de paso enlazan notas estables","Su duración únicamente","Su registro"], a:1, fb:"Puntos estables: tiempos fuertes, duraciones largas, grados I y VI. Notas de paso: tiempos débiles, duraciones cortas, enlazan dos notas reales. La posición métrica es un indicio clave." },
{ q:"Armonizar cada nota con un acorde diferente crea:", opts:["Una bella armonía rica","Un ritmo armónico demasiado rápido que desorienta el oído","Mayor claridad tonal","Un acompañamiento más fácil de escribir"], a:1, fb:"Demasiados cambios de acordes crean caos armónico. La melodía contiene notas extrañas que no exigen un nuevo acorde — ignorarlo sobrecarga la armonización." },
{ q:"En G mayor, la sensible es:", opts:["F natural","F# (Fa sostenido)","G","A"], a:1, fb:"G mayor armónico eleva el VII grado: F natural se convierte en F#. F# es la sensible de G mayor — sube por semitono hacia G (la tónica)." },

{ q:"Una nota de paso enlaza dos notas reales:", opts:["Por un salto de tercera","Por movimiento conjunto en un tiempo débil","Por un salto de quinta","Por semitono cromático siempre"], a:1, fb:"La nota de paso es conjunta (segunda) y generalmente en tiempo débil. Crea una unión melódica fluida entre dos notas reales." },
{ q:"Una bordadura se define como:", opts:["Una nota que abandona el acorde por salto","Una nota rodeada de dos notas idénticas — parte y regresa a la misma nota real","Una nota que anticipa el acorde siguiente","Una nota prolongada"], a:1, fb:"La bordadura abandona una nota real por un semitono o un tono, y luego regresa a ella. Es el más simple de los adornos." },
{ q:"El retardo se coloca en:", opts:["Un tiempo débil","Un tiempo fuerte — preparado, disonante, luego resuelto","Cualquier tiempo","Siempre antes de la barra de compás"], a:1, fb:"El retardo llega en un tiempo fuerte — es lo que le da su fuerza. Preparado → disonante → resuelto." },
{ q:"En V7 → I, si F se mantiene durante el acorde de C, es:", opts:["Una anticipación","Un retardo 4–3 — F desciende hacia E","Una bordadura","Una nota de paso"], a:1, fb:"F es la cuarta que retarda la tercera E de C. Retardo clásico 4→3 sobre la tónica." },
{ q:"La anticipación es:", opts:["Una nota prolongada de un acorde anterior","La nota del acorde siguiente introducida con antelación","Una nota extraña resuelta por salto","Siempre en un tiempo fuerte"], a:1, fb:"La anticipación toca una nota del acorde siguiente antes de que llegue. No necesita resolución — ya es la nota correcta." },
{ q:"La apoyatura difiere del retardo porque:", opts:["No está preparada — llega en un tiempo fuerte sin haber sido escuchada antes","Está en tiempo débil","Nunca es disonante","No se resuelve"], a:0, fb:"El retardo está preparado. La apoyatura no está preparada — llega bruscamente en un tiempo fuerte y se resuelve conjuntamente. Más dramática." },
{ q:"La escapada se caracteriza por:", opts:["Llegada por salto, resolución conjunta","Llegada conjunta, resolución por salto (disjunto)","Dos movimientos conjuntos","Dos saltos"], a:1, fb:"La escapada llega conjuntamente y luego se escapa por un salto. Su efecto de sorpresa proviene de esta resolución inesperada." },
{ q:"Identificar las notas extrañas sirve para:", opts:["Encontrar errores en la melodía","No poner un acorde bajo cada nota — simplificar la armonización","Transportar la melodía","Identificar el modo"], a:1, fb:"Las notas extrañas adornan el acorde en curso sin necesitar uno propio. Identificarlas evita un ritmo armónico demasiado rápido." },
{ q:"En C–D–E–D–C sobre el acorde de C mayor, D es:", opts:["Una nota real","Nota de paso (C→D→E) luego nota de paso descendente (E→D→C)","Siempre un error","Una apoyatura"], a:1, fb:"D entre C y E = nota de paso ascendente. D entre E y C = nota de paso descendente. En ambos casos, D adorna la estructura C–E–C." },
{ q:"Un retardo típico en una cadencia V–I es:", opts:["La quinta que permanece","La séptima que sube","La cuarta que desciende hacia la tercera (4–3)","La fundamental que salta"], a:2, fb:"El retardo 4–3 es clásico sobre la tónica: F (cuarta) → E (tercera) sobre C. Uno de los retardos más frecuentes de la música tonal." },
{ q:"Entre estos ejemplos, ¿cuál es una nota de paso?", opts:["E tenida durante C→G","D entre C y E sobre el acorde de C","G tocada antes de G7","B que desciende hacia C en G7→C"], a:1, fb:"D entre C y E = nota de paso conjunta ascendente. Las demás son: nota tenida (nota real), anticipación, y sensible (nota real de G7)." },
{ q:"¿Por qué los retardos están en los tiempos fuertes?", opts:["Por convención arbitraria","El tiempo fuerte amplifica la disonancia — la resolución es tanto más satisfactoria","Los tiempos débiles están reservados a los acordes","Es más fácil de escribir"], a:1, fb:"En un tiempo fuerte, la disonancia es más perceptible. La resolución que sigue es más satisfactoria. El efecto expresivo del retardo depende de esta posición métrica." },
{ q:"La melodía C–D–E–G–E–D–C sobre el acorde de C: ¿cuáles son las notas reales?", opts:["Todas","C, E y G (la tríada de C) — D es nota de paso","C y D solamente","G y D solamente"], a:1, fb:"C–E–G = tríada de C mayor. D aparece entre C y E (NP ascendente) y entre E y C (NP descendente). D no requiere cambio de acorde." },
{ q:"En G7, la nota B durante un acorde de G7 es:", opts:["Una nota extraña","Una nota real — B es la tercera de G7","Una bordadura","Un retardo"], a:1, fb:"G7 = G–B–D–F. B es la tercera de G7 — es una nota real, no extraña." },
{ q:"La apoyatura se encuentra frecuentemente en las notas:", opts:["Graves de la melodía","Agudas de la melodía y en los tiempos fuertes — da una acentuación expresiva","Siempre cromáticas","Siempre dentro del acorde"], a:1, fb:"La apoyatura es una nota expresiva colocada en un tiempo fuerte — a menudo en un punto culminante melódico. Su llegada no preparada y su resolución conjunta le dan su carácter patético." },
{ q:"En la melodía E–F–G–A sobre el acorde de C mayor, F es:", opts:["Nota real","Nota de paso entre E y G","Apoyatura","Retardo"], a:1, fb:"E y G son notas reales de C mayor. F está entre ellas — nota de paso conjunta ascendente. No se necesita un nuevo acorde." },
{ q:"La diferencia entre bordadura y nota de paso es:", opts:["La bordadura regresa a su nota de partida; la nota de paso va hacia una nota diferente","Son idénticas","La bordadura está en tiempo fuerte","La nota de paso usa saltos"], a:0, fb:"Bordadura: parte de una nota y regresa a la misma. Nota de paso: parte de una nota y continúa hacia una nota diferente. La bordadura oscila; la nota de paso avanza." },
{ q:"¿Qué adorno está preparado (escuchado en el acorde anterior)?", opts:["La apoyatura","La anticipación","El retardo","La escapada"], a:2, fb:"El retardo es la única nota extraña preparada — se escucha en el acorde anterior antes de volverse disonante. La apoyatura llega sin preparación." },
{ q:"Una melodía con muchas notas extrañas necesita:", opts:["Muchos acordes diferentes","Un ritmo armónico más lento — los adornos no exigen nuevos acordes","Un tempo más rápido","Únicamente acordes invertidos"], a:1, fb:"Una melodía ornamentada puede apoyarse en muy pocos acordes. Las notas extrañas enriquecen la línea sin cambiar la armonía — de ahí la importancia de identificarlas antes de armonizar." },
{ q:"La anticipación generalmente está en:", opts:["El tiempo fuerte","El tiempo débil (antes de la barra o el cambio de acorde)","La dominante","El VI grado"], a:1, fb:"La anticipación precede al acorde — está en el tiempo débil justo antes del cambio. Crea un efecto de ligera prisa hacia la nueva armonía." },

{ q:"El esqueleto armónico es:", opts:["La melodía sola","La organización a 3–4 voces que da cuerpo a la progresión","La línea de bajo únicamente","El acompañamiento rítmico"], a:1, fb:"El esqueleto armónico es la realización a varias voces de la progresión — antes de cualquier elección estilística. Comprueba la solidez de la estructura armónica." },
{ q:"La línea de bajo debe ser sólida en las cadencias porque:", opts:["Siempre está doblada","Las cadencias perfectas exigen V y I en estado fundamental","Siempre toca la quinta","El bajo siempre está en octava"], a:1, fb:"La cadencia perfecta (V→I) exige los dos acordes en estado fundamental. El bajo toca las fundamentales — G y C — para confirmar la resolución sin ambigüedad." },
{ q:"Las inversiones en el bajo sirven para:", opts:["Hacer el acorde inestable","Crear una línea de bajo melódica y conjunta","Doblar la melodía","Evitar las disonancias"], a:1, fb:"Una inversión coloca una tercera o quinta en el bajo — permitiendo líneas de bajo conjuntas y melódicas en lugar de saltos entre fundamentales." },
{ q:"Las voces intermedias (alto y tenor) tienen el papel de:", opts:["Doblar la melodía","Completar el acorde y asegurar la continuidad del tejido polifónico","Crear tensiones","Tocar en solo"], a:1, fb:"Alto y tenor completan el acorde — tercera, quinta, séptima según el contexto. Su movimiento debe ser fluido y preferiblemente conjunto." },
{ q:"El movimiento preferido entre el bajo y las voces superiores es:", opts:["Paralelo","Contrario — una voz sube, la otra baja","Oblicuo siempre","Siempre en tercera paralela"], a:1, fb:"El movimiento contrario maximiza la independencia polifónica y evita de manera natural las paralelas. Es el movimiento más equilibrado." },
{ q:"La regla de doblamiento en un acorde en estado fundamental es:", opts:["Doblar la tercera","Doblar la quinta","Doblar la fundamental (salvo excepciones)","Doblar la séptima"], a:2, fb:"La fundamental es la nota más estable — se dobla por defecto. Excepción: VII grado → doblar su tercera (nunca la sensible)." },
{ q:"En I6 (primera inversión de I), el bajo toca:", opts:["La fundamental","La tercera","La quinta","La séptima"], a:1, fb:"I6 = primera inversión: la tercera está en el bajo. En C mayor, C/E tiene E (Mi) en el bajo." },
{ q:"Las notas comunes entre dos acordes deben:", opts:["Evitarse","Conservarse en la misma voz — simplifican la conducción de voces","Subir una segunda","Doblarse"], a:1, fb:"Conservar las notas comunes reduce los desplazamientos. Ej.: C → Am: C y E son comunes. Mantenerlas en su lugar fluidifica la escritura." },
{ q:"¿Qué movimiento está prohibido entre todas las voces?", opts:["Los movimientos conjuntos","Las quintas y octavas paralelas","El movimiento contrario","Los movimientos disjuntos"], a:1, fb:"Las quintas y octavas paralelas anulan la independencia de las voces — dan la ilusión de que dos voces son una sola. Prohibido en escritura estricta." },
{ q:"La sensible (VII grado) debe obligatoriamente:", opts:["Descender hacia el VI grado","Subir hacia la tónica por semitono","Permanecer inmóvil","Saltar hacia la quinta"], a:1, fb:"La sensible sube obligatoriamente hacia la tónica — es la regla absoluta. En C mayor: B → C. Este semitono ascendente es la atracción melódica fundamental." },
{ q:"La séptima de dominante (F en G7) debe:", opts:["Subir hacia G","Descender hacia E (tercera de I) por grado conjunto","Permanecer en F","Saltar hacia C"], a:1, fb:"La séptima de dominante desciende conjuntamente hacia la tercera del acorde siguiente. F → E en G7 → C. Regla absoluta: la séptima de dominante desciende." },
{ q:"¿Cuál es la regla sobre el espaciado entre soprano y alto?", opts:["No más de dos octavas","No más de una octava","Exactamente una tercera","No hay regla"], a:1, fb:"Entre soprano y alto, y entre alto y tenor: máximo una octava. Entre tenor y bajo: hasta dos octavas permitidas." },
{ q:"El principio 'menos movimiento = mejor escritura' significa:", opts:["Escribir el menor número de notas posible","Usar las notas comunes y los movimientos conjuntos — moverse solo si es necesario","No usar nunca inversiones","Todas las voces permanecen inmóviles"], a:1, fb:"Una buena conducción de voces conserva las notas comunes, avanza por grados conjuntos y se mueve solo cuando es musicalmente necesario." },
{ q:"En I6/4 (segunda inversión de I), el bajo toca:", opts:["La fundamental","La tercera","La quinta","La séptima"], a:2, fb:"La segunda inversión (6/4) coloca la quinta en el bajo. C/G en C mayor: G (Sol) en el bajo. Es el 6/4 de cadencia — prepara la dominante." },
{ q:"El doblamiento de la séptima está:", opts:["Obligado","Prohibido — la séptima nunca se dobla","Recomendado","Posible en movimiento contrario"], a:1, fb:"La séptima nunca se dobla — debe resolver conjuntamente hacia el acorde siguiente. Dos séptimas que resolvieran hacia dos notas idénticas crearían octavas paralelas." },
{ q:"¿Qué cruzamiento está prohibido en la escritura a 4 voces?", opts:["El alto que supera momentáneamente al tenor","Ninguno — las voces pueden cruzarse libremente","Las voces no deben cruzarse nunca — el soprano permanece siempre por encima del alto, etc.","Solo el bajo puede superar al tenor"], a:2, fb:"Las voces no se cruzan: S > A > T > B en todo momento. Un cruzamiento borra la independencia de las voces y crea confusión polifónica." },
{ q:"Un solapamiento de voces es:", opts:["Cuando dos voces tocan la misma nota","Cuando una voz supera la nota que la voz adyacente acaba de abandonar","Cuando las voces tocan en octava","Cuando una voz salta una octava"], a:1, fb:"El solapamiento: A toca una nota más alta que la que S acaba de abandonar (o viceversa). Crea confusión sobre la identidad de las voces — prohibido en escritura estricta." },
{ q:"La progresión C–Am–F–G es funcionalmente:", opts:["T–T–SD–D","T–D–SD–T","T–T–SD–T","SD–D–T–D"], a:0, fb:"C = tónica (I), Am = tónica (VI), F = subdominante (IV), G = dominante (V). C–Am–F–G = T–T–SD–D — una progresión muy frecuente en pop." },
{ q:"¿Por qué el bajo y la melodía no deben confundirse frecuentemente?", opts:["Por razones de registro","Porque eso rigidiza el discurso — se pierde la riqueza del diálogo entre los dos extremos","Porque está prohibido","Porque siempre tocan en octavas"], a:1, fb:"Cuando el bajo y la melodía tocan las mismas notas, se pierde la riqueza del diálogo entre los registros extremos. Un discreto contracanto del bajo es más vivo que un doblamiento." },
{ q:"En la progresión II–V–I, ¿qué notas de Dm7 se conservan en G7?", opts:["Ninguna","F y A — F está en G7, A no está en G7 pero puede permanecer","F y C — F está en G7 (séptima) y C puede descender hacia B","D y A"], a:2, fb:"Dm7 = D–F–A–C. G7 = G–B–D–F. Notas comunes: D y F. F permanece como séptima de G7. D permanece como quinta de G7. A y C se mueven hacia G y B." },
{ q:"Una cadencia perfecta exige:", opts:["Al menos un acorde invertido","V y I en estado fundamental (fundamentales en el bajo)","El VII grado","Un acorde de sexta"], a:1, fb:"La cadencia perfecta requiere V y I en estado fundamental — las fundamentales G y C en el bajo. Cualquier inversión la transforma en cadencia imperfecta." },
{ q:"El 6/4 de cadencia (I6/4) se utiliza:", opts:["En lugar de la dominante","Justo antes de la dominante — prepara V7 como una doble apoyatura","Como tónica final","Al comienzo de cada frase"], a:1, fb:"El 6/4 de cadencia (C/G) precede a G7 — sus notas G y E son la quinta y la tercera de G7. Actúa como una doble apoyatura ascendente de la quinta y la tercera de la dominante." },
{ q:"La tesitura del soprano en la escritura SATB es:", opts:["G3 a C5","C4 a G5","C3 a G4","E2 a C4"], a:1, fb:"Soprano: C4 (Do medio) a G5. Alto: G3 a C5. Tenor: C3 a G4. Bajo: E2 a C4. Estas tesituras garantizan la comodidad vocal y el equilibrio acústico." },
{ q:"¿Qué es una quinta directa (o quinta de batida)?", opts:["Dos voces que forman una quinta por movimiento conjunto","Dos voces exteriores (S y B) que alcanzan una quinta por movimiento directo (misma dirección)","Dos quintas consecutivas","Una quinta disminuida"], a:1, fb:"La quinta directa: soprano y bajo se mueven en la misma dirección y llegan a una quinta. Está prohibida entre las voces extremas — tolerada únicamente si el soprano avanza por grados conjuntos." },
{ q:"La progresión I–V6–I6–IV–V7–I usa inversiones para:", opts:["Hacer los acordes inestables","Crear una línea de bajo ascendente conjunta: C–B–C–F–G–C","Evitar la dominante","Doblar la melodía"], a:1, fb:"V6 = G/B, I6 = C/E. Bajo: C→B→C→F→G→C — línea melódica variada e interesante gracias a las inversiones." },

{ q:"El acompañamiento se construye a partir de:", opts:["Nada — se improvisa libremente","El esqueleto armónico, del cual es la puesta en forma expresiva","La melodía únicamente","El ritmo únicamente"], a:1, fb:"El acompañamiento se apoya en el esqueleto armónico — es su traducción estilística. Sostiene y amplifica la curva de tensión musical." },
{ q:"El arpegio se caracteriza por:", opts:["Acordes ejecutados simultáneamente","El despliegue regular de las notas del acorde en el tiempo","Síncopes rítmicas","Contrapuntos independientes"], a:1, fb:"El arpegio despliega las notas del acorde en el tiempo — en lugar de simultáneamente. Crea una continuidad fluida característica de las baladas y nocturnos." },
{ q:"El comping proviene del:", opts:["Barroco","Clasicismo vienés","Jazz — acordes puntuales en los contratiempos con mucho silencio","Romanticismo"], a:2, fb:"El comping es una técnica del jazz — acordes cortos, sincopados, con silencio expresivo. El espacio entre los acordes es tan importante como los acordes mismos." },
{ q:"¿Qué parámetro aumenta la tensión en un acompañamiento?", opts:["Menos notas","Un tempo más lento","Mayor densidad — más notas y ritmos más rápidos","Un ámbito reducido"], a:2, fb:"La tensión aumenta con la densidad — más notas por compás, síncopes, ritmo armónico rápido, ámbito amplio." },
{ q:"El ámbito de un acompañamiento designa:", opts:["El número de voces","La distancia entre la nota más grave y la nota más aguda","El registro medio","La duración de cada nota"], a:1, fb:"El ámbito es la extensión del acompañamiento. Amplio = tensión dramática. Reducido = compresión dinámica y atmósfera íntima." },
{ q:"Las notas extrañas en el acompañamiento:", opts:["Debilitan la armonía","Crean intensidad — retardos, apoyaturas añaden disonancias expresivas resueltas","Deben evitarse","No tienen ningún efecto"], a:1, fb:"Las notas extrañas enriquecen el acompañamiento — un retardo o una apoyatura crea una micro-tensión que se resuelve, añadiendo expresión a cada acorde." },
{ q:"El estilo bajo–acorde separado es típico de:", opts:["La fuga barroca","El vals — bajo en 1, acorde en 2 y 3","El nocturno romántico","La tocata"], a:1, fb:"El vals utiliza bajo(1)–acorde(2)–acorde(3). Este patrón ancla el primer tiempo y crea el balanceo característico." },
{ q:"Un acompañamiento en contrapunto exige:", opts:["Pocos conocimientos de armonía","El dominio de la conducción de voces — cada línea es melódicamente autónoma","Únicamente acordes plaqués","La improvisación"], a:1, fb:"El contrapunto trata cada voz como una línea independiente. Es la forma más compleja — exige un dominio total de la conducción de voces." },
{ q:"Un buen acompañamiento nunca contradice:", opts:["El tempo","La curva de tensión musical de la melodía","La tonalidad","El registro del cantante"], a:1, fb:"El acompañamiento debe ser coherente con la dinámica de tensión de la melodía — la anuncia, la acompaña o la prolonga." },
{ q:"La repetición de un motivo en el acompañamiento crea:", opts:["Tensión","Estabilidad — la repetición ancla y tranquiliza el oyente, creando un fondo previsible sobre el que la melodía puede destacar","Modulación","Confusión tonal"], a:1, fb:"La repetición de un motivo de acompañamiento crea un marco estable — el oyente se familiariza con el patrón y puede concentrarse en la melodía. Es el principio del ostinato." },
];

const questionsDe: Question[] = [{ q:"Was ist das Erste, das man analysieren muss, um das tonale Zentrum zu identifizieren?", opts:["Das Tempo","Die Vorzeichen","Die Länge","Das Register"], a:1, fb:"Die Vorzeichen zeigen sofort die wahrscheinlichen Tonarten an – die Durtonleiter und ihre relative Molltonart. Das ist der erste Anhaltspunkt der Tonalitätsanalyse." },
{ q:"2 Kreuze (F# und C#) entsprechen der Tonart:", opts:["G-Dur oder E-Moll","D-Dur oder H-Moll","A-Dur oder F#-Moll","B-Dur oder G-Moll"], a:1, fb:"2 Kreuze = Vorzeichen von D-Dur / H-Moll. F# und C# sind die charakteristischen Vorzeichen dieser beiden Tonleitern." },
{ q:"Der Leitton ist erkennbar an:", opts:["Einem Terzsprung","Einem Halbtonschritt aufwärts zu einer stabilen Note","Einer langen Haltung","Einem Quintsprung"], a:1, fb:"Der Leitton ist die VII. harmonische Stufe – er steigt um einen Halbton zur Tonika. Das ist die stärkste melodische Anziehungskraft der Tonleiter." },
{ q:"Eine auf einer betonten Zählzeit gehaltene Note am Phrasenbeginn entspricht oft:", opts:["Der Dominante","Der VII. Stufe","Der I. oder VI. Stufe – Stabilitätspolen","Einer Fremdnote"], a:2, fb:"Stabile Noten auf betonten Zählzeiten entsprechen den Stufen I und VI – den Tonika-Polen. Die Melodie ruht dort auf natürliche Weise." },
{ q:"Eine über mehrere Takte verlängerte Akzidentalie deutet hin auf:", opts:["Eine kurze Ausleihe","Eine mögliche Modulation","Einen Notationsfehler","Einen Vorhalt"], a:1, fb:"Kurze Akzidentalie = Ausleihe. Verlängert = das tonale Zentrum kann sich verändert haben – Zeichen einer Modulation in eine neue Tonart." },
{ q:"Die Schlusskadenz ist zur Identifikation des tonalen Zentrums nützlich, weil:", opts:["Sie immer V7–I ist","Sie die tatsächliche Auflösung zeigt – die lokale I. Stufe","Sie Ganze Noten verwendet","Sie immer in Dur ist"], a:1, fb:"Die Schlusskadenz zeigt, wie sich die Phrase auflöst. Die I. Stufe der Kadenz ist das lokale tonale Zentrum." },
{ q:"Das harmonische Rhythmus ist:", opts:["Die Metronomgeschwindigkeit","Die Häufigkeit des Akkordwechsels","Die Anzahl der Noten pro Takt","Die Taktart"], a:1, fb:"Der harmonische Rhythmus ist die Häufigkeit, mit der die Akkorde wechseln – unabhängig vom Tempo." },
{ q:"Warum entsprechen nicht zwingend alle Noten einer Melodie dem Akkord?", opts:["Weil die Melodie falsch sein kann","Weil manche Fremdnoten sind – Ornamente, die nicht zum Akkord gehören","Weil der Akkord immer umgekehrt ist","Weil Akzidentalien alles verändern"], a:1, fb:"Die Melodie enthält oft Fremdnoten. Sie zu erkennen verhindert, unnötige Akkorde zu häufen." },
{ q:"'Echte Noten' (notes réelles) sind:", opts:["Doppelt gespielte Noten","Noten, die zum aktuellen Harmonieakkord gehören","Noten ohne Vorzeichen","Bassnoten"], a:1, fb:"Echte Noten gehören zum Akkord – sie bilden die harmonische Struktur. Die anderen schmücken diese Struktur." },
{ q:"Eine Ausleihe unterscheidet sich von einer Modulation, weil:", opts:["Die Ausleihe umgekehrte Akkorde verwendet","Die Ausleihe momentan ist und das tonale Zentrum nicht verlagert","Die Ausleihe immer V7–I folgt","Die Ausleihe den Neapolitaner verwendet"], a:1, fb:"Eine Ausleihe ist kurz. Eine Modulation etabliert dauerhaft eine neue Tonart – bestätigt durch eine vollständige Kadenz im neuen Zentrum." },
{ q:"Die Tonart F-Dur hat wie viele Bs?", opts:["Keine","Eines (B♭)","Zwei (B♭, E♭)","Drei"], a:1, fb:"F-Dur hat ein B: B♭. Das ist die Vorzeichen mit einem B – die Tonleiter F G A B♭ C D E F." },
{ q:"Eine Melodie, die sich um G dreht und zu A♭ aufsteigt, deutet hin auf:", opts:["C-Dur","A♭-Dur oder F-Moll","G-Dur","D-Moll"], a:1, fb:"G → A♭ ist ein aufsteigender Halbton: G wirkt als Leitton von A♭. Die Tonart ist wahrscheinlich A♭-Dur oder F-Moll (Parallele)." },
{ q:"Eine Molltonart unterscheidet sich von der gleichnamigen Durtonart in der Melodie durch:", opts:["Nur ihre Vorzeichen","Das wiederholte Auftreten der kleinen III. Stufe und des spezifischen Leittons","Ihr Tempo","Ihr Register"], a:1, fb:"In Moll kreist die Melodie um die kleine Terz (Eb in C-Moll) und den harmonischen Leitton (H natürlich). Diese Noten charakterisieren den Mollmodus auch ohne Vorzeichen." },
{ q:"Welche Melodie deutet eher auf C-Dur als auf A-Moll hin?", opts:["Eine Melodie, die auf A endet","Eine Melodie, die auf C beginnt und endet, mit häufigen Stützpunkten auf E und G","Eine Melodie mit vielen tiefen Noten","Eine Melodie in Triolen"], a:1, fb:"Wenn die Melodie auf C (Tonika), E (Terz) und G (Quinte) verankert ist und auf C endet, ist die Tonart C-Dur. Wenn sie auf A verankert ist, ist es A-Moll." },
{ q:"Der harmonische Rhythmus einer Ballade ist typischerweise:", opts:["Ein Akkord pro Note","Ein Akkord pro Takt oder Halbtakt","Ein Akkord pro Achtel","Kein regelmäßiger Akkord"], a:1, fb:"Eine Ballade wechselt die Akkorde langsam – oft einmal pro Takt. Jeder Akkord hat Zeit, sich im Ohr zu etablieren." },
{ q:"Eine Tonikalisierung erkennt man in der Melodie an:", opts:["Einer langen Haltung","Einem künstlichen Leitton – Halbtonschritt aufwärts zu einer nicht-tonischen Stufe","Einem Quintsprung","Einem Vorhalt"], a:1, fb:"Eine Tonikalisierung schafft einen vorübergehenden Leitton zu einem nicht-tonischen Akkord. Bsp.: C# (Leitton von D) gefolgt von D in einer Melodie in G-Dur = Tonikalisierung von Dm." },
{ q:"Wenn die Melodie in einer Tonart mit 0 Kreuzen ein F# enthält, ist das wahrscheinlich:", opts:["Ein Fehler","Eine Tonikalisierung von G (dessen Leitton F# ist) oder eine Ausleihe","Eine Broderie-Note","Die Grundton eines Akkords"], a:1, fb:"In C-Dur ist F# außerhalb der Tonleiter. Es ist wahrscheinlich der Leitton von G (V), der eine Tonikalisierung V/V schafft – oder eine Ausleihe. Das nachfolgende G bestätigt die Tonikalisierung." },
{ q:"Was unterscheidet 'stabile Punkte' von Durchgangsnoten in einer Melodie?", opts:["Ihre Tonhöhe","Stabile Punkte liegen auf betonten Zählzeiten und den Stufen I/VI – Durchgangsnoten verbinden stabile Noten","Nur ihre Dauer","Ihr Register"], a:1, fb:"Stabile Punkte: betonte Zählzeiten, lange Dauern, Stufen I und VI. Durchgangsnoten: unbetonte Zählzeiten, kurze Dauern, verbinden zwei echte Noten. Die metrische Position ist ein Schlüsselindiz." },
{ q:"Jede Note mit einem anderen Akkord zu harmonisieren erzeugt:", opts:["Eine schöne reiche Harmonie","Einen zu schnellen harmonischen Rhythmus, der das Ohr desorientiert","Mehr tonale Klarheit","Eine einfacher zu schreibende Begleitung"], a:1, fb:"Zu viele Akkordwechsel erzeugen harmonisches Chaos. Die Melodie enthält Fremdnoten, die keinen neuen Akkord erfordern – das zu ignorieren überlastet die Harmonisierung." },
{ q:"In G-Dur ist der Leitton:", opts:["F natürlich","F# (Fis)","G","A"], a:1, fb:"G-Dur harmonisch erhöht die VII. Stufe: F natürlich wird zu F#. F# ist der Leitton von G-Dur – er steigt um einen Halbton zur Tonika G." },

{ q:"Eine Durchgangsnote verbindet zwei echte Noten:", opts:["Durch einen Terzsprung","Durch Sekundschritt auf einer unbetonten Zählzeit","Durch einen Quintsprung","Immer durch chromatischen Halbton"], a:1, fb:"Die Durchgangsnote ist stufenweise (Sekunde) und generell auf einer unbetonten Zählzeit. Sie schafft eine fließende melodische Verbindung zwischen zwei echten Noten." },
{ q:"Eine Broderie (Wechselnote) ist definiert als:", opts:["Eine Note, die den Akkord durch Sprung verlässt","Eine von zwei identischen Noten umgebene Note – sie verlässt die echte Note und kehrt zu ihr zurück","Eine Note, die den nächsten Akkord antizipiert","Eine verlängerte Note"], a:1, fb:"Die Broderie verlässt eine echte Note um einen Halb- oder Ganzton und kehrt zu ihr zurück. Es ist der einfachste der Ornamente." },
{ q:"Der Vorhalt liegt auf:", opts:["Einer unbetonten Zählzeit","Einer betonten Zählzeit – vorbereitet, dissonant, dann aufgelöst","Beliebiger Zählzeit","Immer vor dem Taktstrich"], a:1, fb:"Der Vorhalt kommt auf einer betonten Zählzeit – das ist es, was ihm seine Kraft gibt. Vorbereitet → dissonant → aufgelöst." },
{ q:"In V7 → I, wenn F während des C-Akkords gehalten wird, ist das:", opts:["Eine Antizipation","Ein Vorhalt 4–3 – F steigt ab zu E","Eine Broderie","Eine Durchgangsnote"], a:1, fb:"F ist die Quarte, die die Terz E von C verzögert. Klassischer Vorhalt 4→3 auf der Tonika." },
{ q:"Die Antizipation ist:", opts:["Eine verlängerte Note eines vorherigen Akkords","Die Note des nächsten Akkords, die im Voraus eingeführt wird","Eine durch Sprung aufgelöste Fremdnote","Immer auf einer betonten Zählzeit"], a:1, fb:"Die Antizipation spielt eine Note des nächsten Akkords, bevor er eintrifft. Sie braucht keine Auflösung – es ist bereits die richtige Note." },
{ q:"Die Appoggiatura unterscheidet sich vom Vorhalt, weil:", opts:["Sie nicht vorbereitet ist – sie kommt auf einer betonten Zählzeit ohne vorher gehört worden zu sein","Sie auf einer unbetonten Zählzeit liegt","Sie nie dissonant ist","Sie sich nicht auflöst"], a:0, fb:"Der Vorhalt ist vorbereitet. Die Appoggiatura ist nicht vorbereitet – sie kommt abrupt auf einer betonten Zählzeit und löst sich stufenweise auf. Dramatischer." },
{ q:"Die Échappée (Überwurfnote) ist charakterisiert durch:", opts:["Ankunft durch Sprung, Auflösung stufenweise","Ankunft stufenweise, Auflösung durch Sprung (disjunkt)","Zwei stufenweise Bewegungen","Zwei Sprünge"], a:1, fb:"Die Échappée kommt stufenweise und entweicht dann durch einen Sprung. Ihr Überraschungseffekt kommt von dieser unerwarteten Auflösung." },
{ q:"Fremdnoten zu identifizieren dient dazu:", opts:["Fehler in der Melodie zu finden","Nicht unter jede Note einen Akkord zu setzen – die Harmonisierung zu vereinfachen","Die Melodie zu transponieren","Den Modus zu identifizieren"], a:1, fb:"Fremdnoten schmücken den aktuellen Akkord, ohne einen eigenen zu benötigen. Sie zu identifizieren verhindert einen zu schnellen harmonischen Rhythmus." },
{ q:"In C–D–E–D–C über Akkord C-Dur ist D:", opts:["Eine echte Note","Durchgangsnote (C→D→E) und absteigende Durchgangsnote (E→D→C)","Immer ein Fehler","Eine Appoggiatura"], a:1, fb:"D zwischen C und E = aufsteigende Durchgangsnote. D zwischen E und C = absteigende Durchgangsnote. In beiden Fällen schmückt D die Struktur C–E–C." },
{ q:"Ein typischer Vorhalt in einer V–I-Kadenz ist:", opts:["Die verbleibende Quinte","Die aufsteigende Septime","Die absteigende Quarte zur Terz (4–3)","Die springende Grundton"], a:2, fb:"Der Vorhalt 4–3 ist klassisch auf der Tonika: F (Quarte) → E (Terz) auf C. Einer der häufigsten Vorhalte in der Tonalmusik." },
{ q:"Welches dieser Beispiele ist eine Durchgangsnote?", opts:["E gehalten während C→G","D zwischen C und E über Akkord C","G gespielt vor G7","B das zu C absteigt auf G7→C"], a:1, fb:"D zwischen C und E = aufsteigende stufenweise Durchgangsnote. Die anderen sind: Haltung (echte Note), Antizipation und Leitton (echte Note von G7)." },
{ q:"Warum liegen Vorhalte auf betonten Zählzeiten?", opts:["Aus willkürlicher Konvention","Die betonte Zählzeit verstärkt die Dissonanz – die Auflösung ist umso befriedigender","Unbetonte Zählzeiten sind für Akkorde reserviert","Es ist einfacher zu notieren"], a:1, fb:"Auf einer betonten Zählzeit ist die Dissonanz wahrnehmbarer. Die folgende Auflösung ist befriedigender. Die expressive Wirkung des Vorhalts hängt von dieser metrischen Position ab." },
{ q:"Die Melodie C–D–E–G–E–D–C über Akkord C: Welches sind die echten Noten?", opts:["Alle","C, E und G (die Dreiklang C) – D ist Durchgangsnote","Nur C und D","Nur G und D"], a:1, fb:"C–E–G = C-Dur-Dreiklang. D erscheint zwischen C und E (aufsteigende DN) und zwischen E und C (absteigende DN). D erfordert keinen Akkordwechsel." },
{ q:"In G7 ist die Note B während eines G7-Akkords:", opts:["Eine Fremdnote","Eine echte Note – B ist die Terz von G7","Eine Broderie","Ein Vorhalt"], a:1, fb:"G7 = G–B–D–F. B ist die Terz von G7 – das ist eine echte Note, keine Fremdnote." },
{ q:"Die Appoggiatura liegt oft auf:", opts:["Tiefen Noten der Melodie","Hohen Noten der Melodie und auf betonten Zählzeiten – sie gibt eine expressive Betonung","Immer chromatischen Noten","Immer im Akkord"], a:1, fb:"Die Appoggiatura ist eine expressive Note auf einer betonten Zählzeit – oft auf einem melodischen Höhepunkt. Ihre unvorbereitete Ankunft und stufenweise Auflösung verleihen ihr ihren pathetischen Charakter." },
{ q:"In der Melodie E–F–G–A über Akkord C-Dur ist F:", opts:["Eine echte Note","Eine Durchgangsnote zwischen E und G","Eine Appoggiatura","Ein Vorhalt"], a:1, fb:"E und G sind echte Noten von C-Dur. F liegt zwischen ihnen – aufsteigende stufenweise Durchgangsnote. Kein neuer Akkord nötig." },
{ q:"Der Unterschied zwischen Broderie und Durchgangsnote ist:", opts:["Die Broderie kehrt zur Ausgangsnote zurück; die Durchgangsnote geht zu einer anderen Note","Sie sind identisch","Die Broderie liegt auf einer betonten Zählzeit","Die Durchgangsnote verwendet Sprünge"], a:0, fb:"Broderie: verlässt eine Note und kehrt zur gleichen zurück. Durchgangsnote: verlässt eine Note und geht zu einer anderen weiter. Die Broderie oszilliert; die Durchgangsnote schreitet voran." },
{ q:"Welches Ornament ist vorbereitet (im vorherigen Akkord gehört)?", opts:["Die Appoggiatura","Die Antizipation","Der Vorhalt","Die Échappée"], a:2, fb:"Der Vorhalt ist die einzige vorbereitete Fremdnote – er wird im vorherigen Akkord gehört, bevor er dissonant wird. Die Appoggiatura kommt ohne Vorbereitung." },
{ q:"Eine Melodie mit vielen Fremdnoten erfordert:", opts:["Viele verschiedene Akkorde","Einen langsameren harmonischen Rhythmus – die Ornamente erfordern keine neuen Akkorde","Ein schnelleres Tempo","Nur umgekehrte Akkorde"], a:1, fb:"Eine ornamentierte Melodie kann auf sehr wenigen Akkorden beruhen. Fremdnoten bereichern die Linie ohne die Harmonie zu ändern – daher ist ihre Identifizierung vor dem Harmonisieren wichtig." },
{ q:"Die Antizipation liegt generell auf:", opts:["Der betonten Zählzeit","Der unbetonten Zählzeit (vor dem Taktstrich oder dem Akkordwechsel)","Der Dominante","Der VI. Stufe"], a:1, fb:"Die Antizipation geht dem Akkord voraus – sie liegt auf der unbetonten Zählzeit kurz vor dem Wechsel. Sie erzeugt einen leichten Vorwärtsdrang zur neuen Harmonie." },

{ q:"Das harmonische Gerüst ist:", opts:["Die Melodie allein","Die 3–4-stimmige Organisation, die der Progression Substanz verleiht","Nur die Basslinie","Die rhythmische Begleitung"], a:1, fb:"Das harmonische Gerüst ist die mehrstimmige Realisierung der Progression – vor jeder stilistischen Entscheidung. Es prüft die Solidität der harmonischen Struktur." },
{ q:"Die Basslinie muss an Kadenzen solide sein, weil:", opts:["Sie immer verdoppelt wird","Vollständige Kadenzen V und I im Grundstellung erfordern","Sie immer die Quinte spielt","Der Bass immer oktaviert wird"], a:1, fb:"Die vollständige Kadenz (V→I) erfordert beide Akkorde in Grundstellung. Der Bass spielt die Grundtöne – G und C – um die Auflösung eindeutig zu bestätigen." },
{ q:"Umkehrungen im Bass dienen dazu:", opts:["Den Akkord instabil zu machen","Eine melodische und stufenweise Basslinie zu schaffen","Die Melodie zu verdoppeln","Dissonanzen zu vermeiden"], a:1, fb:"Eine Umkehrung platziert eine Terz oder Quinte im Bass – was stufenweise und melodische Basslinien statt Sprünge zwischen Grundtönen ermöglicht." },
{ q:"Die Mittelstimmen (Alt und Tenor) haben die Aufgabe:", opts:["Die Melodie zu verdoppeln","Den Akkord zu vervollständigen und die Kontinuität des polyphonen Geflechts zu sichern","Spannungen zu erzeugen","Solo zu spielen"], a:1, fb:"Alt und Tenor vervollständigen den Akkord – Terz, Quinte, Septime je nach Kontext. Ihre Bewegung soll fließend und vorzugsweise stufenweise sein." },
{ q:"Die bevorzugte Bewegung zwischen Bass und Oberstimmen ist:", opts:["Parallel","Gegenbewegung – eine Stimme steigt, die andere fällt","Immer oblique","Immer in parallelen Terzen"], a:1, fb:"Die Gegenbewegung maximiert die polyphone Unabhängigkeit und vermeidet natürlich Parallelen. Es ist die ausgewogenste Bewegung." },
{ q:"Die Verdoppelungsregel in einem Akkord in Grundstellung lautet:", opts:["Die Terz verdoppeln","Die Quinte verdoppeln","Den Grundton verdoppeln (mit Ausnahmen)","Die Septime verdoppeln"], a:2, fb:"Der Grundton ist die stabilste Note – er wird standardmäßig verdoppelt. Ausnahme: VII. Stufe → seine Terz verdoppeln (nie den Leitton)." },
{ q:"In I6 (erste Umkehrung von I) spielt der Bass:", opts:["Den Grundton","Die Terz","Die Quinte","Die Septime"], a:1, fb:"I6 = erste Umkehrung: die Terz liegt im Bass. In C-Dur hat C/E das E im Bass." },
{ q:"Gemeinsame Noten zwischen zwei Akkorden sollten:", opts:["Vermieden werden","In der gleichen Stimme beibehalten werden – sie vereinfachen die Stimmführung","Um eine Sekunde aufsteigen","Verdoppelt werden"], a:1, fb:"Gemeinsame Noten beizubehalten reduziert die Bewegungen. Bsp.: C → Am: C und E sind gemeinsam. Sie an Ort zu lassen macht den Satz fließender." },
{ q:"Welche Bewegung ist zwischen allen Stimmen verboten?", opts:["Stufenweise Bewegungen","Parallele Quinten und Oktaven","Gegenbewegung","Disjunkte Bewegungen"], a:1, fb:"Parallele Quinten und Oktaven heben die Unabhängigkeit der Stimmen auf – sie erwecken den Eindruck, als wären zwei Stimmen eine. In strenger Schreibweise verboten." },
{ q:"Der Leitton (VII. Stufe) muss zwingend:", opts:["Zur VI. Stufe absteigen","Durch Halbton zur Tonika aufsteigen","Stillbleiben","Zur Quinte springen"], a:1, fb:"Der Leitton steigt zwingend zur Tonika auf – das ist die absolute Regel. In C-Dur: H → C. Dieser aufsteigende Halbton ist die fundamentale melodische Anziehungskraft." },
{ q:"Die Dominantseptime (F in G7) muss:", opts:["Zu G aufsteigen","Stufenweise zur Terz von I absteigen (F → E)","Auf F bleiben","Zu C springen"], a:1, fb:"Die Dominantseptime steigt stufenweise zur Terz des nächsten Akkords ab. F → E auf G7 → C. Absolute Regel: die Dominantseptime steigt ab." },
{ q:"Was ist die Regel bezüglich des Abstands zwischen Sopran und Alt?", opts:["Nicht mehr als zwei Oktaven","Nicht mehr als eine Oktave","Genau eine Terz","Keine Regel"], a:1, fb:"Zwischen Sopran und Alt sowie zwischen Alt und Tenor: maximal eine Oktave. Zwischen Tenor und Bass: bis zu zwei Oktaven erlaubt." },
{ q:"Das Prinzip 'weniger Bewegung = besserer Satz' bedeutet:", opts:["So wenig Noten wie möglich zu schreiben","Gemeinsame Noten und stufenweise Bewegungen zu nutzen – nur zu bewegen wenn nötig","Niemals Umkehrungen zu verwenden","Alle Stimmen bleiben stillstehen"], a:1, fb:"Eine gute Stimmführung bewahrt gemeinsame Noten, schreitet stufenweise fort und bewegt sich nur, wenn es musikalisch notwendig ist." },
{ q:"In I6/4 (zweite Umkehrung von I) spielt der Bass:", opts:["Den Grundton","Die Terz","Die Quinte","Die Septime"], a:2, fb:"Die 2. Umkehrung (6/4) platziert die Quinte im Bass. C/G in C-Dur: G im Bass. Das ist der Quartsextakkord der Kadenz – er bereitet die Dominante vor." },
{ q:"Die Verdoppelung der Septime ist:", opts:["Obligatorisch","Verboten – die Septime wird nie verdoppelt","Empfohlen","Möglich in Gegenbewegung"], a:1, fb:"Die Septime wird nie verdoppelt – sie muss stufenweise zum nächsten Akkord auflösen. Zwei Septimen, die zu zwei identischen Noten auflösen, würden parallele Oktaven erzeugen." },
{ q:"Welche Überkreuzung ist im vierstimmigen Satz verboten?", opts:["Der Alt, der den Tenor vorübergehend überschreitet","Keine – die Stimmen können sich frei kreuzen","Die Stimmen dürfen sich nie kreuzen – Sopran bleibt immer über dem Alt usw.","Nur der Bass darf den Tenor überschreiten"], a:2, fb:"Die Stimmen kreuzen sich nicht: S > A > T > B jederzeit. Eine Kreuzung hebt die Unabhängigkeit der Stimmen auf und erzeugt polyphone Verwirrung." },
{ q:"Eine Stimmüberschneidung ist:", opts:["Wenn zwei Stimmen die gleiche Note spielen","Wenn eine Stimme die Note übersteigt, die die benachbarte Stimme gerade verlassen hat","Wenn die Stimmen in Oktaven spielen","Wenn eine Stimme eine Oktave springt"], a:1, fb:"Die Überschneidung: A spielt eine höhere Note als die, die S gerade verlassen hat (oder umgekehrt). Sie erzeugt Verwirrung über die Identität der Stimmen – in strenger Schreibweise verboten." },
{ q:"Die Progression C–Am–F–G ist funktional:", opts:["T–T–SD–D","T–D–SD–T","T–T–SD–T","SD–D–T–D"], a:0, fb:"C = Tonika (I), Am = Tonika (VI), F = Subdominante (IV), G = Dominante (V). C–Am–F–G = T–T–SD–D – eine sehr häufige Progression in der Popmusik." },
{ q:"Warum sollten Bass und Melodie nicht oft zusammenfallen?", opts:["Aus Registergründen","Weil das den Diskurs versteift – man verliert den Reichtum des Dialogs zwischen den beiden Extremen","Weil es verboten ist","Weil sie immer in Oktaven spielen"], a:1, fb:"Wenn Bass und Melodie die gleichen Noten spielen, verliert man den Reichtum des Dialogs zwischen den Extremregistern. Ein diskretes Gegenmotiv des Basses ist lebendiger als eine Verdoppelung." },
{ q:"Welche Noten von Dm7 bleiben in der Progression II–V–I in G7 erhalten?", opts:["Keine","F und A – F ist in G7, A nicht, kann aber bleiben","F und C – F ist in G7 (Septime) und C kann zu B absteigen","D und A"], a:2, fb:"Dm7 = D–F–A–C. G7 = G–B–D–F. Gemeinsame Noten: D und F. F bleibt als Septime von G7. D bleibt als Quinte von G7. A und C bewegen sich zu G und B." },
{ q:"Eine vollständige Kadenz erfordert:", opts:["Mindestens einen umgekehrten Akkord","V und I in Grundstellung (Grundtöne im Bass)","Die VII. Stufe","Einen Sextakkord"], a:1, fb:"Die vollständige Kadenz erfordert V und I in Grundstellung – die Grundtöne G und C im Bass. Jede Umkehrung verwandelt sie in eine unvollständige Kadenz." },
{ q:"Der Quartsextakkord (I6/4) wird verwendet:", opts:["Anstelle der Dominante","Kurz vor der Dominante – er bereitet V7 als doppelte Appoggiatura vor","Als abschließende Tonika","Zu Beginn jeder Phrase"], a:1, fb:"Der Quartsextakkord (C/G) geht G7 voraus – seine Noten G und E sind die Quinte und Terz von G7. Er wirkt als doppelte aufsteigende Appoggiatura der Quinte und Terz der Dominante." },
{ q:"Die Tessitura des Soprans im SATB-Satz ist:", opts:["G3 bis C5","C4 bis G5","C3 bis G4","E2 bis C4"], a:1, fb:"Sopran: C4 bis G5. Alt: G3 bis C5. Tenor: C3 bis G4. Bass: E2 bis C4. Diese Tessituren gewährleisten vokalen Komfort und akustische Ausgewogenheit." },
{ q:"Was ist eine Direktquinte (oder Hornquinte)?", opts:["Zwei Stimmen, die eine Quinte durch Stufenbewegung bilden","Zwei Außenstimmen (S und B), die durch direkte Bewegung (gleiche Richtung) eine Quinte erreichen","Zwei aufeinanderfolgende Quinten","Eine verminderte Quinte"], a:1, fb:"Die Direktquinte: Sopran und Bass bewegen sich in dieselbe Richtung und erreichen eine Quinte. Verboten zwischen den Außenstimmen — nur toleriert, wenn der Sopran sich schrittweise bewegt." },
];

const questionsIt: Question[] = [{ q:"Qual è la prima cosa da analizzare per identificare il centro tonale?", opts:["Il tempo","L'armatura di chiave","La lunghezza","Il registro"], a:1, fb:"L'armatura di chiave indica immediatamente le tonalità probabili — la scala maggiore e la sua relativa minore. È il primo riferimento dell'analisi tonale." },
{ q:"2 diesis (F# e C#) corrispondono alla tonalità di:", opts:["G maggiore o E minore","D maggiore o B minore","A maggiore o F# minore","B♭ maggiore o G minore"], a:1, fb:"2 diesis = armatura di D maggiore / B minore. F# e C# sono le alterazioni costitutive di queste due scale." },
{ q:"La sensibile si riconosce da:", opts:["Un salto di terza","Un semitono ascendente verso una nota stabile","Una lunga tenuta","Un salto di quinta"], a:1, fb:"La sensibile è il VII grado armonico — sale di un semitono verso la tonica. È l'attrazione melodica più forte della scala." },
{ q:"Una nota tenuta su un tempo forte all'inizio di una frase corrisponde spesso a:", opts:["La dominante","Il VII grado","Il I o VI grado — poli di stabilità","Una nota estranea"], a:2, fb:"Le note stabili sui tempi forti corrispondono ai gradi I e VI — i poli tonici. La melodia vi si riposa naturalmente." },
{ q:"Un'alterazione accidentale prolungata su più misure indica:", opts:["Un prestito momentaneo","Una possibile modulazione","Un errore di notazione","Un ritardo"], a:1, fb:"Alterazione momentanea = prestito. Prolungata = il centro tonale potrebbe essere cambiato — segnale di una modulazione verso una nuova tonalità." },
{ q:"La cadenza finale è utile per identificare il centro tonale perché:", opts:["È sempre V7–I","Rivela la risoluzione reale — il grado I locale","Usa le semibrevi","È sempre in maggiore"], a:1, fb:"La cadenza finale mostra come la frase si risolve. Il grado I della cadenza è il centro tonale locale." },
{ q:"Il ritmo armonico è:", opts:["La velocità del metronomo","La frequenza di cambiamento degli accordi","Il numero di note per misura","Il tipo di misura"], a:1, fb:"Il ritmo armonico è la frequenza con cui gli accordi cambiano — indipendentemente dal tempo." },
{ q:"Perché non tutte le note di una melodia corrispondono necessariamente all'accordo?", opts:["Perché la melodia può essere sbagliata","Perché alcune sono note estranee — ornamenti che non fanno parte dell'accordo","Perché l'accordo è sempre rivolto","Perché le alterazioni cambiano tutto"], a:1, fb:"La melodia contiene spesso note estranee. Identificarle evita di sovrapporre accordi inutili." },
{ q:"Le 'note reali' sono:", opts:["Le note suonate in doppio","Le note che appartengono all'accordo armonico in corso","Le note senza alterazione","Le note del basso"], a:1, fb:"Le note reali appartengono all'accordo — costituiscono la struttura armonica. Le altre ornano questa struttura." },
{ q:"Un prestito differisce da una modulazione perché:", opts:["Il prestito usa accordi rivolti","Il prestito è momentaneo e non sposta il centro tonale","Il prestito segue sempre V7–I","Il prestito usa il napoletano"], a:1, fb:"Un prestito è breve. Una modulazione installa durevolmente una nuova tonalità — confermata da una cadenza perfetta nel nuovo centro." },
{ q:"La tonalità di F maggiore ha quanti bemolli?", opts:["Nessuno","Uno (B♭)","Due (B♭, E♭)","Tre"], a:1, fb:"F maggiore ha un bemolle: Si♭ (B♭). È l'armatura con un bemolle — la scala F G A B♭ C D E F." },
{ q:"La melodia che ruota intorno a G e sale verso A♭ suggerisce:", opts:["C maggiore","A♭ maggiore o F minore","G maggiore","D minore"], a:1, fb:"G → A♭ è un semitono ascendente: G agisce come sensibile di A♭. La tonalità è probabilmente A♭ maggiore o F minore (relativa)." },
{ q:"Una tonalità minore si distingue da una maggiore omonima nella melodia per:", opts:["La sola armatura di chiave","La presenza ricorrente del III grado minore e della sensibile specifica","Il suo tempo","Il suo registro"], a:1, fb:"In minore, la melodia gravita intorno alla terza minore (Eb in C minore) e alla sensibile armonica (B naturale). Queste note caratterizzano il modo minore anche senza armatura." },
{ q:"Quale melodia suggerisce C maggiore piuttosto che A minore?", opts:["Una melodia che finisce su A","Una melodia che inizia e finisce su C, con appoggi frequenti su E e G","Una melodia con molte note gravi","Una melodia in terzine"], a:1, fb:"Se la melodia si ancora su C (tonica), E (terza) e G (quinta) e termina su C, la tonalità è C maggiore. Se si ancora su A, è A minore." },
{ q:"Il ritmo armonico di una ballata è tipicamente:", opts:["Un accordo per nota","Un accordo per misura o mezza misura","Un accordo per ottavo","Nessun accordo regolare"], a:1, fb:"Una ballata cambia accordo lentamente — spesso una volta per misura. Ogni accordo ha il tempo di installarsi nell'orecchio." },
{ q:"La tonicizzazione si riconosce nella melodia da:", opts:["Una lunga tenuta","Una sensibile artificiale — semitono ascendente verso un grado non tonico","Un salto di quinta","Un ritardo"], a:1, fb:"Una tonicizzazione crea una sensibile temporanea verso un accordo non tonico. Es.: C# (sensibile di D) seguito da D in una melodia in G maggiore = tonicizzazione di Dm." },
{ q:"Se la melodia contiene un F# in una tonalità a 0 diesis, è probabilmente:", opts:["Un errore","Una tonicizzazione di G (di cui F# è la sensibile) o un prestito","Una nota di broderie","La fondamentale di un accordo"], a:1, fb:"In C maggiore, F# è fuori scala. È probabilmente la sensibile di G (V), creando una tonicizzazione V/V — o un prestito. La presenza di G che segue conferma la tonicizzazione." },
{ q:"Cosa differenzia i 'punti stabili' dalle note di passaggio in una melodia?", opts:["La loro altezza","I punti stabili sono sui tempi forti e sui gradi I/VI — le note di passaggio collegano note stabili","La loro sola durata","Il loro registro"], a:1, fb:"Punti stabili: tempi forti, lunghe durate, gradi I e VI. Note di passaggio: tempi deboli, durate brevi, collegano due note reali. La posizione metrica è un indice chiave." },
{ q:"Armonizzare ogni nota con un accordo diverso crea:", opts:["Una bella armonia ricca","Un ritmo armonico troppo rapido che disorientà l'orecchio","Maggiore chiarezza tonale","Un accompagnamento più facile da scrivere"], a:1, fb:"Troppi cambi di accordo creano caos armonico. La melodia contiene note estranee che non richiedono un nuovo accordo — ignorarlo sovraccarica l'armonizzazione." },
{ q:"In G maggiore, la sensibile è:", opts:["F naturale","F# (Fa diesis)","G","A"], a:1, fb:"G maggiore armonico eleva il VII grado: F naturale diventa F#. F# è la sensibile di G maggiore — sale per semitono verso G (la tonica)." },

{ q:"Una nota di passaggio collega due note reali:", opts:["Per un salto di terza","Per moto congiunto su un tempo debole","Per un salto di quinta","Per semitono cromatico sempre"], a:1, fb:"La nota di passaggio è congiunta (seconda) e generalmente su tempo debole. Crea un collegamento melodico fluido tra due note reali." },
{ q:"Una broderie si definisce come:", opts:["Una nota che lascia l'accordo per salto","Una nota circondata da due note identiche — parte e ritorna sulla stessa nota reale","Una nota che anticipa l'accordo successivo","Una nota prolungata"], a:1, fb:"La broderie lascia una nota reale per un semitono o un tono, poi vi ritorna. È il più semplice degli ornamenti." },
{ q:"Il ritardo si colloca su:", opts:["Un tempo debole","Un tempo forte — preparato, dissonante, poi risolto","Qualsiasi tempo","Sempre prima della stanghetta"], a:1, fb:"Il ritardo arriva su un tempo forte — è questo che gli conferisce la sua forza. Preparato → dissonante → risolto." },
{ q:"In V7 → I, se F è tenuto durante l'accordo di C, è:", opts:["Un'anticipazione","Un ritardo 4–3 — F scende verso E","Una broderie","Una nota di passaggio"], a:1, fb:"F è la quarta che ritarda la terza E di C. Ritardo classico 4→3 sulla tonica." },
{ q:"L'anticipazione è:", opts:["Una nota prolungata di un accordo precedente","La nota dell'accordo successivo introdotta in anticipo","Una nota estranea risolta per salto","Sempre su un tempo forte"], a:1, fb:"L'anticipazione suona una nota dell'accordo successivo prima che arrivi. Non ha bisogno di risoluzione — è già la nota giusta." },
{ q:"L'appoggiatura differisce dal ritardo perché:", opts:["Non è preparata — arriva su un tempo forte senza essere stata udita prima","È su tempo debole","Non è mai dissonante","Non si risolve"], a:0, fb:"Il ritardo è preparato. L'appoggiatura non è preparata — arriva bruscamente su un tempo forte e si risolve per moto congiunto. Più drammatica." },
{ q:"L'échappée si caratterizza per:", opts:["Arrivo per salto, risoluzione congiunta","Arrivo congiunto, risoluzione per salto (disjunto)","Due movimenti congiunti","Due salti"], a:1, fb:"L'échappée arriva per moto congiunto poi si allontana per salto. Il suo effetto di sorpresa viene da questa risoluzione inattesa." },
{ q:"Identificare le note estranee serve a:", opts:["Trovare errori nella melodia","Non mettere un accordo sotto ogni nota — semplificare l'armonizzazione","Trasportare la melodia","Identificare il modo"], a:1, fb:"Le note estranee ornano l'accordo in corso senza averne bisogno di uno proprio. Identificarle evita un ritmo armonico troppo rapido." },
{ q:"In C–D–E–D–C sull'accordo di C maggiore, D è:", opts:["Una nota reale","Nota di passaggio (C→D→E) poi nota di passaggio discendente (E→D→C)","Sempre un errore","Un'appoggiatura"], a:1, fb:"D tra C e E = nota di passaggio ascendente. D tra E e C = nota di passaggio discendente. In entrambi i casi, D orna la struttura C–E–C." },
{ q:"Un ritardo tipico in una cadenza V–I è:", opts:["La quinta che rimane","La settima che sale","La quarta che scende verso la terza (4–3)","La fondamentale che salta"], a:2, fb:"Il ritardo 4–3 è classico sulla tonica: F (quarta) → E (terza) su C. Uno dei ritardi più frequenti della musica tonale." },
{ q:"Tra questi esempi, quale è una nota di passaggio?", opts:["E tenuto durante C→G","D tra C e E sull'accordo C","G suonato prima di G7","B che scende verso C su G7→C"], a:1, fb:"D tra C e E = nota di passaggio congiunta ascendente. Le altre sono: tenuta (nota reale), anticipazione, e sensibile (nota reale di G7)." },
{ q:"Perché i ritardi sono sui tempi forti?", opts:["Per convenzione arbitraria","Il tempo forte amplifica la dissonanza — la risoluzione è tanto più soddisfacente","I tempi deboli sono riservati agli accordi","È più facile da notare"], a:1, fb:"Su un tempo forte, la dissonanza è più percepibile. La risoluzione che segue è più soddisfacente. L'effetto espressivo del ritardo dipende da questa posizione metrica." },
{ q:"La melodia C–D–E–G–E–D–C sull'accordo C: quali sono le note reali?", opts:["Tutte","C, E e G (la triade C) — D è nota di passaggio","Solo C e D","Solo G e D"], a:1, fb:"C–E–G = triade C maggiore. D appare tra C e E (NP ascendente) e tra E e C (NP discendente). D non richiede un cambio di accordo." },
{ q:"In G7, la nota B durante un accordo di G7 è:", opts:["Una nota estranea","Una nota reale — B è la terza di G7","Una broderie","Un ritardo"], a:1, fb:"G7 = G–B–D–F. B è la terza di G7 — è una nota reale, non estranea." },
{ q:"L'appoggiatura è spesso sulle note:", opts:["Gravi della melodia","Acute della melodia e sui tempi forti — dà un'accentuazione espressiva","Sempre cromatiche","Sempre nell'accordo"], a:1, fb:"L'appoggiatura è una nota espressiva posta su un tempo forte — spesso su un culmine melodico. Il suo arrivo non preparato e la sua risoluzione congiunta le conferiscono il carattere patetico." },
{ q:"Nella melodia E–F–G–A sull'accordo di C maggiore, F è:", opts:["Nota reale","Nota di passaggio tra E e G","Appoggiatura","Ritardo"], a:1, fb:"E e G sono note reali di C maggiore. F è tra di esse — nota di passaggio congiunta ascendente. Non serve un nuovo accordo." },
{ q:"La differenza tra broderie e nota di passaggio è:", opts:["La broderie ritorna sulla nota di partenza; la nota di passaggio va verso una nota diversa","Sono identiche","La broderie è sul tempo forte","La nota di passaggio usa salti"], a:0, fb:"Broderie: parte da una nota e ritorna sulla stessa. Nota di passaggio: parte da una nota e prosegue verso una nota diversa. La broderie oscilla; la nota di passaggio avanza." },
{ q:"Quale ornamento è preparato (udito nell'accordo precedente)?", opts:["L'appoggiatura","L'anticipazione","Il ritardo","L'échappée"], a:2, fb:"Il ritardo è l'unica nota estranea preparata — viene udita nell'accordo precedente prima di diventare dissonante. L'appoggiatura arriva senza preparazione." },
{ q:"Una melodia con molte note estranee necessita:", opts:["Molti accordi diversi","Un ritmo armonico più lento — gli ornamenti non richiedono nuovi accordi","Un tempo più rapido","Solo accordi rivolti"], a:1, fb:"Una melodia ornata può appoggiarsi su pochissimi accordi. Le note estranee arricchiscono la linea senza cambiare l'armonia — da qui l'importanza di identificarle prima di armonizzare." },
{ q:"L'anticipazione è generalmente su:", opts:["Il tempo forte","Il tempo debole (prima della stanghetta o del cambio di accordo)","La dominante","Il VI grado"], a:1, fb:"L'anticipazione precede l'accordo — è sul tempo debole subito prima del cambio. Crea un effetto di lieve slancio verso la nuova armonia." },

{ q:"Lo scheletro armonico è:", opts:["La sola melodia","L'organizzazione a 3–4 voci che dà corpo alla progressione","La sola linea del basso","L'accompagnamento ritmico"], a:1, fb:"Lo scheletro armonico è la realizzazione a più voci della progressione — prima di qualsiasi scelta stilistica. Mette alla prova la solidità della struttura armonica." },
{ q:"La linea del basso deve essere solida alle cadenze perché:", opts:["È sempre raddoppiata","Le cadenze perfette richiedono V e I in stato fondamentale","Suona sempre la quinta","Il basso è sempre all'ottava"], a:1, fb:"La cadenza perfetta (V→I) richiede entrambi gli accordi in stato fondamentale. Il basso suona le fondamentali — G e C — per confermare la risoluzione senza ambiguità." },
{ q:"I rivolti al basso servono a:", opts:["Rendere l'accordo instabile","Creare una linea di basso melodica e congiunta","Raddoppiare la melodia","Evitare le dissonanze"], a:1, fb:"Un rivolto pone una terza o quinta al basso — permettendo linee di basso congiunte e melodiche piuttosto che salti tra fondamentali." },
{ q:"Le voci intermedie (contralto e tenore) hanno il ruolo di:", opts:["Raddoppiare la melodia","Completare l'accordo e assicurare la continuità del tessuto polifonico","Creare tensioni","Suonare da soli"], a:1, fb:"Contralto e tenore completano l'accordo — terza, quinta, settima a seconda del contesto. Il loro movimento deve essere fluido e preferibilmente congiunto." },
{ q:"Il movimento preferito tra basso e voci superiori è:", opts:["Parallelo","Contrario — una voce sale, l'altra scende","Obliquo sempre","Sempre in terza parallela"], a:1, fb:"Il movimento contrario massimizza l'indipendenza polifonica ed evita naturalmente i paralleli. È il movimento più equilibrato." },
{ q:"La regola di raddoppio in un accordo in stato fondamentale è:", opts:["Raddoppiare la terza","Raddoppiare la quinta","Raddoppiare la fondamentale (salvo eccezioni)","Raddoppiare la settima"], a:2, fb:"La fondamentale è la nota più stabile — si raddoppia per impostazione predefinita. Eccezione: VII grado → raddoppiare la sua terza (mai la sensibile)." },
{ q:"In I6 (primo rivolto di I), il basso suona:", opts:["La fondamentale","La terza","La quinta","La settima"], a:1, fb:"I6 = primo rivolto: la terza è al basso. In C maggiore, C/E ha E (Mi) al basso." },
{ q:"Le note comuni tra due accordi devono:", opts:["Essere evitate","Essere conservate nella stessa voce — semplificano la conduzione delle voci","Salire di una seconda","Essere raddoppiate"], a:1, fb:"Conservare le note comuni riduce gli spostamenti. Es.: C → Am: C e E sono comuni. Tenerle ferme fluidifica la scrittura." },
{ q:"Quale movimento è vietato tra tutte le voci?", opts:["I movimenti congiunti","Le quinte e ottave parallele","Il movimento contrario","I movimenti disgiunti"], a:1, fb:"Le quinte e ottave parallele annullano l'indipendenza delle voci — danno l'illusione che due voci siano una sola. Vietato in scrittura rigorosa." },
{ q:"La sensibile (VII grado) deve obbligatoriamente:", opts:["Scendere verso il VI grado","Salire verso la tonica per semitono","Restare immobile","Saltare verso la quinta"], a:1, fb:"La sensibile sale obbligatoriamente verso la tonica — è la regola assoluta. In C maggiore: B → C. Questo semitono ascendente è l'attrazione melodica fondamentale." },
{ q:"La settima di dominante (F in G7) deve:", opts:["Salire verso G","Scendere verso E (terza di I) per grado congiunto","Restare su F","Saltare verso C"], a:1, fb:"La settima di dominante scende per grado congiunto verso la terza dell'accordo successivo. F → E su G7 → C. Regola assoluta: la settima di dominante scende." },
{ q:"Qual è la regola riguardante la spaziatura tra soprano e contralto?", opts:["Non più di due ottave","Non più di un'ottava","Esattamente una terza","Nessuna regola"], a:1, fb:"Tra soprano e contralto, e tra contralto e tenore: massimo un'ottava. Tra tenore e basso: fino a due ottave consentite." },
{ q:"Il principio 'meno movimenti = scrittura migliore' significa:", opts:["Scrivere il minor numero di note possibile","Usare le note comuni e i movimenti congiunti — muoversi solo se necessario","Non usare mai i rivolti","Tutte le voci restano immobili"], a:1, fb:"Una buona conduzione delle voci conserva le note comuni, procede per gradi congiunti e si muove solo quando è musicalmente necessario." },
{ q:"In I6/4 (secondo rivolto di I), il basso suona:", opts:["La fondamentale","La terza","La quinta","La settima"], a:2, fb:"Il 2° rivolto (6/4) pone la quinta al basso. C/G in C maggiore: G (Sol) al basso. È il 6/4 di cadenza — prepara la dominante." },
{ q:"Il raddoppio della settima è:", opts:["Obbligatorio","Vietato — la settima non si raddoppia mai","Raccomandato","Possibile in movimento contrario"], a:1, fb:"La settima non si raddoppia mai — deve risolvere per grado congiunto verso l'accordo successivo. Due settime che risolvono verso due note identiche creerebbero ottave parallele." },
{ q:"Quale incrocio è vietato nella scrittura a 4 voci?", opts:["Il contralto che supera momentaneamente il tenore","Nessuno — le voci possono incrociarsi liberamente","Le voci non devono mai incrociarsi — il soprano resta sempre sopra il contralto, ecc.","Solo il basso può superare il tenore"], a:2, fb:"Le voci non si incrociano: S > A > T > B in ogni momento. Un incrocio cancella l'indipendenza delle voci e crea confusione polifonica." },
{ q:"Un sorpasso di voce è:", opts:["Quando due voci suonano la stessa nota","Quando una voce supera la nota che la voce adiacente ha appena abbandonato","Quando le voci suonano all'ottava","Quando una voce salta di un'ottava"], a:1, fb:"Il sorpasso: il contralto suona una nota più alta di quella che il soprano ha appena abbandonato (o viceversa). Crea confusione sull'identità delle voci — vietato in scrittura rigorosa." },
{ q:"La progressione C–Am–F–G è funzionalmente:", opts:["T–T–SD–D","T–D–SD–T","T–T–SD–T","SD–D–T–D"], a:0, fb:"C = tonica (I), Am = tonica (VI), F = sottodominante (IV), G = dominante (V). C–Am–F–G = T–T–SD–D — una progressione molto comune nel pop." },
{ q:"Perché basso e melodia non devono spesso confondersi?", opts:["Per ragioni di registro","Perché ciò irrigidirebbe il discorso — si perderebbe la ricchezza del dialogo tra i due estremi","Perché è vietato","Perché suonano sempre all'ottava"], a:1, fb:"Quando basso e melodia suonano le stesse note, si perde la ricchezza del dialogo tra i registri estremi. Un controcanto discreto del basso è più vivace di un raddoppio." },
{ q:"Nella progressione II–V–I, quali note di Dm7 si conservano in G7?", opts:["Nessuna","F e A — F è in G7, A non è in G7 ma può restare","F e C — F è in G7 (settima) e C può scendere verso B","D e A"], a:2, fb:"Dm7 = D–F–A–C. G7 = G–B–D–F. Note comuni: D e F. F resta come settima di G7. D resta come quinta di G7. A e C si muovono verso G e B." },
{ q:"Una cadenza perfetta richiede:", opts:["Almeno un accordo rivolto","V e I in stato fondamentale (fondamentali al basso)","Il VII grado","Un accordo di sesta"], a:1, fb:"La cadenza perfetta richiede V e I in stato fondamentale — le fondamentali G e C al basso. Qualsiasi rivolto la trasforma in cadenza imperfetta." },
{ q:"Il 6/4 di cadenza (I6/4) viene usato:", opts:["Al posto della dominante","Subito prima della dominante — prepara V7 come doppia appoggiatura","Come tonica finale","All'apertura di ogni frase"], a:1, fb:"Il 6/4 di cadenza (C/G) precede G7 — le sue note G e E sono la quinta e la terza di G7. Agisce come doppia appoggiatura ascendente della quinta e della terza della dominante." },
{ q:"La tessitura del soprano nella scrittura SATB è:", opts:["G3–C5","C4–G5","C3–G4","E2–C4"], a:1, fb:"Soprano: C4 (Do medio) a G5. Contralto: G3 a C5. Tenore: C3 a G4. Basso: E2 a C4. Queste tessiture garantiscono il comfort vocale e l'equilibrio acustico." },
{ q:"Cos'è una quinta diretta (o quinta di battuta)?", opts:["Due voci che formano una quinta per moto congiunto","Due voci esterne (S e B) che raggiungono una quinta per moto diretto (stessa direzione)","Due quinte consecutive","Una quinta diminuita"], a:1, fb:"La quinta diretta: soprano e basso si muovono nella stessa direzione e arrivano su una quinta. È vietata tra le voci estreme — tollerata solo se il soprano avanza per gradi congiunti." },
{ q:"La progressione I–V6–I6–IV–V7–I usa i rivolti per:", opts:["Rendere gli accordi instabili","Creare una linea di basso ascendente congiunta: C–B–C–F–G–C","Evitare la dominante","Raddoppiare la melodia"], a:1, fb:"V6 = G/B, I6 = C/E. Basso: C→B→C→F→G→C — linea melodica varia e interessante grazie ai rivolti." },

{ q:"L'accompagnamento è costruito a partire da:", opts:["Nulla — è improvvisato liberamente","Lo scheletro armonico, di cui è la messa in forma espressiva","La sola melodia","Il solo ritmo"], a:1, fb:"L'accompagnamento si basa sullo scheletro armonico — ne è la traduzione stilistica. Sostiene e amplifica la curva di tensione musicale." },
{ q:"L'arpeggio è caratterizzato da:", opts:["Accordi suonati simultaneamente","Lo spiegamento regolare delle note dell'accordo nel tempo","Sincopi ritmiche","Contrappunti indipendenti"], a:1, fb:"L'arpeggio dispiega le note dell'accordo nel tempo — piuttosto che simultaneamente. Crea una continuità fluida caratteristica delle ballate e dei notturni." },
{ q:"Il comping proviene dal:", opts:["Barocco","Classicismo viennese","Jazz — accordi puntuali sui controttempi con molto silenzio","Romanticismo"], a:2, fb:"Il comping è una tecnica jazz — accordi brevi, sincopati, con silenzi espressivi. Lo spazio tra gli accordi è importante quanto gli accordi stessi." },
{ q:"Quale parametro aumenta la tensione in un accompagnamento?", opts:["Meno note","Un tempo più lento","Più densità — più note e ritmi più rapidi","Un ambitus ristretto"], a:2, fb:"La tensione aumenta con la densità — più note per misura, sincopi, ritmo armonico rapido, ambitus ampio." },
{ q:"L'ambitus di un accompagnamento designa:", opts:["Il numero di voci","L'intervallo tra la nota più grave e la nota più acuta","Il registro medio","La durata di ogni nota"], a:1, fb:"L'ambitus è l'estensione dell'accompagnamento. Ampio = tensione drammatica. Ristretto = compressione dinamica e atmosfera intima." },
{ q:"Le note estranee nell'accompagnamento:", opts:["Indeboliscono l'armonia","Creano intensità — ritardi, appoggiature aggiungono dissonanze espressive risolte","Devono essere evitate","Non hanno alcun effetto"], a:1, fb:"Le note estranee arricchiscono l'accompagnamento — un ritardo o un'appoggiatura crea una micro-tensione che si risolve, aggiungendo espressione a ogni accordo." },
{ q:"Lo stile basso–accordo separato è tipico della:", opts:["Fuga barocca","Valse — basso su 1, accordo su 2 e 3","Notturno romantico","Toccata"], a:1, fb:"La valse usa basso(1)–accordo(2)–accordo(3). Questo schema ancora il primo tempo e crea il caratteristico dondolio." },
{ q:"Un accompagnamento in contrappunto richiede:", opts:["Poca conoscenza dell'armonia","La padronanza della conduzione delle voci — ogni linea è melodicamente autonoma","Solo accordi suonati simultaneamente","L'improvvisazione"], a:1, fb:"Il contrappunto tratta ogni voce come una linea indipendente. È la forma più complessa — richiede una padronanza totale della conduzione delle voci." },
];

const questionsPt: Question[] = [{ q:"Qual é a primeira coisa a analisar para identificar o centro tonal?", opts:["O andamento","A armadura","O comprimento","O registro"], a:1, fb:"A armadura indica imediatamente as tonalidades prováveis — a escala maior e sua relativa menor. É o primeiro ponto de referência da análise tonal." },
{ q:"2 sustenidos (F# e C#) correspondem à tonalidade de:", opts:["Sol maior ou Mi menor","Ré maior ou Si menor","Lá maior ou F# menor","Si♭ maior ou Sol menor"], a:1, fb:"2 sustenidos = armadura de Ré maior / Si menor. F# e C# são as alterações constitutivas dessas duas escalas." },
{ q:"A sensível se reconhece por:", opts:["Um salto de terça","Um semitom ascendente em direção a uma nota estável","Uma longa sustentação","Um salto de quinta"], a:1, fb:"A sensível é o VII grau harmônico — ela sobe um semitom em direção à tônica. É a atração melódica mais forte da escala." },
{ q:"Uma nota sustentada em um tempo forte no início de uma frase corresponde frequentemente a:", opts:["A dominante","O VII grau","O I ou VI grau — polos de estabilidade","Uma nota estranha"], a:2, fb:"As notas estáveis nos tempos fortes correspondem aos graus I e VI — os polos tônicos. A melodia se repousa naturalmente neles." },
{ q:"Uma alteração acidental prolongada por vários compassos indica:", opts:["Um empréstimo pontual","Uma possível modulação","Um erro de notação","Um retardo"], a:1, fb:"Alteração pontual = empréstimo. Prolongada = o centro tonal pode ter mudado — sinal de uma modulação para uma nova tonalidade." },
{ q:"A cadência final é útil para identificar o centro tonal porque:", opts:["Ela é sempre V7–I","Ela revela a resolução real — o grau I local","Ela usa semibreves","Ela é sempre em maior"], a:1, fb:"A cadência final mostra como a frase se resolve. O grau I da cadência é o centro tonal local." },
{ q:"O ritmo harmônico é:", opts:["A velocidade do metrônomo","A frequência de mudança dos acordes","O número de notas por compasso","O tipo de compasso"], a:1, fb:"O ritmo harmônico é a frequência com que os acordes mudam — independentemente do andamento." },
{ q:"Por que nem todas as notas de uma melodia correspondem necessariamente ao acorde?", opts:["Porque a melodia pode estar errada","Porque algumas são notas estranhas — ornamentos que não fazem parte do acorde","Porque o acorde está sempre invertido","Porque as alterações mudam tudo"], a:1, fb:"A melodia frequentemente contém notas estranhas. Identificá-las evita empilhar acordes desnecessários." },
{ q:"As 'notas reais' são:", opts:["As notas tocadas em dobro","As notas que pertencem ao acorde harmônico em curso","As notas sem alteração","As notas do baixo"], a:1, fb:"As notas reais pertencem ao acorde — elas constituem a estrutura harmônica. As demais ornamentam essa estrutura." },
{ q:"Um empréstimo difere de uma modulação porque:", opts:["O empréstimo usa acordes invertidos","O empréstimo é momentâneo e não desloca o centro tonal","O empréstimo sempre segue V7–I","O empréstimo usa o napolitano"], a:1, fb:"Um empréstimo é breve. Uma modulação instala duradouramente uma nova tonalidade — confirmada por uma cadência perfeita no novo centro." },
{ q:"A tonalidade de Fá maior tem quantos bemóis?", opts:["Nenhum","Um (B♭)","Dois (B♭, E♭)","Três"], a:1, fb:"Fá maior tem um bemól: Si♭ (B♭). É a armadura com um bemól — a escala F G A B♭ C D E F." },
{ q:"A melodia que gira em torno de G e sobe para A♭ sugere:", opts:["Dó maior","Lá♭ maior ou Fá menor","Sol maior","Ré menor"], a:1, fb:"G → A♭ é um semitom ascendente: G atua como sensível de A♭. A tonalidade é provavelmente Lá♭ maior ou Fá menor (relativa)." },
{ q:"Uma tonalidade menor se distingue de uma maior homônima na melodia por:", opts:["Sua armadura apenas","A presença recorrente do III grau menor e da sensível específica","Seu andamento","Seu registro"], a:1, fb:"No menor, a melodia gravita em torno da terça menor (Eb em Dó menor) e da sensível harmônica (B natural). Essas notas caracterizam o modo menor mesmo sem armadura." },
{ q:"Qual melodia sugere Dó maior em vez de Lá menor?", opts:["Uma melodia que termina em A","Uma melodia que começa e termina em C, com apoios frequentes em E e G","Uma melodia com muitas notas graves","Uma melodia em tercinas"], a:1, fb:"Se a melodia se ancora em C (tônica), E (terça) e G (quinta) e termina em C, a tonalidade é Dó maior. Se se ancora em A, é Lá menor." },
{ q:"O ritmo harmônico de uma balada é tipicamente:", opts:["Um acorde por nota","Um acorde por compasso ou meio compasso","Um acorde por colcheia","Nenhum acorde regular"], a:1, fb:"Uma balada muda de acorde lentamente — geralmente uma vez por compasso. Cada acorde tem tempo de se instalar no ouvido." },
{ q:"A tonicização se reconhece na melodia por:", opts:["Uma longa sustentação","Uma sensível artificial — semitom ascendente em direção a um grau não tônico","Um salto de quinta","Um retardo"], a:1, fb:"Uma tonicização cria uma sensível temporária em direção a um acorde não tônico. Ex: C# (sensível de D) seguido de D em uma melodia em Sol maior = tonicização de Dm." },
{ q:"Se a melodia contém um F# em uma tonalidade com 0 sustenidos, provavelmente é:", opts:["Um erro","Uma tonicização de G (cuja sensível é F#) ou um empréstimo","Uma nota de bordadura","A fundamental de um acorde"], a:1, fb:"Em Dó maior, F# está fora da escala. Provavelmente é a sensível de G (V), criando uma tonicização V/V — ou um empréstimo. A presença de G a seguir confirma a tonicização." },
{ q:"O que diferencia os 'pontos estáveis' das notas de passagem em uma melodia?", opts:["Sua altura","Os pontos estáveis estão nos tempos fortes e nos graus I/VI — as notas de passagem ligam notas estáveis","Sua duração apenas","Seu registro"], a:1, fb:"Pontos estáveis: tempos fortes, longas durações, graus I e VI. Notas de passagem: tempos fracos, durações curtas, ligam duas notas reais. A posição métrica é um índice fundamental." },
{ q:"Harmonizar cada nota com um acorde diferente cria:", opts:["Uma bela harmonia rica","Um ritmo harmônico rápido demais que desorenta o ouvido","Mais clareza tonal","Um acompanhamento mais fácil de escrever"], a:1, fb:"Mudanças de acorde em excesso criam caos harmônico. A melodia contém notas estranhas que não exigem um novo acorde — ignorar isso sobrecarrega a harmonização." },
{ q:"Em Sol maior, a sensível é:", opts:["F natural","F# (Fá sustenido)","G","A"], a:1, fb:"Sol maior harmônico eleva o VII grau: F natural torna-se F#. F# é a sensível de Sol maior — ela sobe por semitom em direção a G (a tônica)." },

{ q:"Uma nota de passagem liga duas notas reais:", opts:["Por um salto de terça","Por movimento conjunto em um tempo fraco","Por um salto de quinta","Por semitom cromático sempre"], a:1, fb:"A nota de passagem é conjunta (segunda) e geralmente em tempo fraco. Ela cria uma ligação melódica fluida entre duas notas reais." },
{ q:"Uma bordadura se define como:", opts:["Uma nota que deixa o acorde por salto","Uma nota cercada por duas notas idênticas — ela parte e retorna à mesma nota real","Uma nota que antecipa o próximo acorde","Uma nota prolongada"], a:1, fb:"A bordadura deixa uma nota real por um semitom ou um tom e depois retorna a ela. É o mais simples dos ornamentos." },
{ q:"O retardo se coloca em:", opts:["Um tempo fraco","Um tempo forte — preparado, dissonante e depois resolvido","Qualquer tempo","Sempre antes da barra de compasso"], a:1, fb:"O retardo chega em um tempo forte — é isso que lhe confere sua força. Preparado → dissonante → resolvido." },
{ q:"Em V7 → I, se F é sustentado durante o acorde de C, é:", opts:["Uma antecipação","Um retardo 4–3 — F desce para E","Uma bordadura","Uma nota de passagem"], a:1, fb:"F é a quarta que retarda a terça E de C. Retardo clássico 4→3 sobre a tônica." },
{ q:"A antecipação é:", opts:["Uma nota prolongada de um acorde anterior","A nota do próximo acorde introduzida com antecedência","Uma nota estranha resolvida por salto","Sempre em um tempo forte"], a:1, fb:"A antecipação toca uma nota do próximo acorde antes que ele chegue. Ela não precisa de resolução — já é a nota correta." },
{ q:"A apojatura difere do retardo porque:", opts:["Ela não é preparada — chega em um tempo forte sem ter sido ouvida antes","Ela está em tempo fraco","Ela nunca é dissonante","Ela não se resolve"], a:0, fb:"O retardo é preparado. A apojatura não é preparada — chega abruptamente em um tempo forte e se resolve por grau conjunto. Mais dramática." },
{ q:"A escapada se caracteriza por:", opts:["Chegada por salto, resolução conjunta","Chegada conjunta, resolução por salto (disjunto)","Dois movimentos conjuntos","Dois saltos"], a:1, fb:"A escapada chega por movimento conjunto e então escapa por um salto. Seu efeito de surpresa vem dessa resolução inesperada." },
{ q:"Identificar as notas estranhas serve para:", opts:["Encontrar erros na melodia","Não colocar um acorde sob cada nota — simplificar a harmonização","Transportar a melodia","Identificar o modo"], a:1, fb:"As notas estranhas ornamentam o acorde em curso sem precisar de um próprio. Identificá-las evita um ritmo harmônico excessivamente rápido." },
{ q:"Em C–D–E–D–C sobre o acorde de Dó maior, D é:", opts:["Uma nota real","Nota de passagem (C→D→E) e depois nota de passagem descendente (E→D→C)","Sempre um erro","Uma apojatura"], a:1, fb:"D entre C e E = nota de passagem ascendente. D entre E e C = nota de passagem descendente. Em ambos os casos, D ornamenta a estrutura C–E–C." },
{ q:"Um retardo típico em uma cadência V–I é:", opts:["A quinta que permanece","A sétima que sobe","A quarta que desce para a terça (4–3)","A fundamental que salta"], a:2, fb:"O retardo 4–3 é clássico sobre a tônica: F (quarta) → E (terça) em C. Um dos retardos mais frequentes da música tonal." },
{ q:"Dentre estes exemplos, qual é uma nota de passagem?", opts:["E sustentado durante C→G","D entre C e E sobre o acorde de C","G tocado antes de G7","B que desce para C em G7→C"], a:1, fb:"D entre C e E = nota de passagem conjunta ascendente. As demais são: sustentação (nota real), antecipação e sensível (nota real de G7)." },
{ q:"Por que os retardos estão nos tempos fortes?", opts:["Por convenção arbitrária","O tempo forte amplifica a dissonância — a resolução é tanto mais satisfatória","Os tempos fracos são reservados aos acordes","É mais fácil de notar"], a:1, fb:"Em um tempo forte, a dissonância é mais perceptível. A resolução que se segue é mais satisfatória. O efeito expressivo do retardo depende dessa posição métrica." },
{ q:"A melodia C–D–E–G–E–D–C sobre o acorde de C: quais são as notas reais?", opts:["Todas","C, E e G (a tríade de C) — D é nota de passagem","Somente C e D","Somente G e D"], a:1, fb:"C–E–G = tríade de Dó maior. D aparece entre C e E (NP ascendente) e entre E e C (NP descendente). D não requer mudança de acorde." },
{ q:"Em G7, a nota B durante o acorde de G7 é:", opts:["Uma nota estranha","Uma nota real — B é a terça de G7","Uma bordadura","Um retardo"], a:1, fb:"G7 = G–B–D–F. B é a terça de G7 — é uma nota real, não estranha." },
{ q:"A apojatura está frequentemente nas notas:", opts:["Graves da melodia","Agudas da melodia e nos tempos fortes — ela confere uma acentuação expressiva","Sempre cromáticas","Sempre dentro do acorde"], a:1, fb:"A apojatura é uma nota expressiva colocada em um tempo forte — frequentemente em um cume melódico. Sua chegada não preparada e sua resolução conjunta lhe conferem caráter patético." },
{ q:"Na melodia E–F–G–A sobre o acorde de Dó maior, F é:", opts:["Nota real","Nota de passagem entre E e G","Apojatura","Retardo"], a:1, fb:"E e G são notas reais de Dó maior. F está entre elas — nota de passagem conjunta ascendente. Não há necessidade de um novo acorde." },
{ q:"A diferença entre bordadura e nota de passagem é:", opts:["A bordadura retorna à sua nota de partida; a nota de passagem vai em direção a uma nota diferente","Elas são idênticas","A bordadura está em tempo forte","A nota de passagem usa saltos"], a:0, fb:"Bordadura: parte de uma nota e retorna à mesma. Nota de passagem: parte de uma nota e continua em direção a uma nota diferente. A bordadura oscila; a nota de passagem avança." },
{ q:"Qual ornamento é preparado (ouvido no acorde anterior)?", opts:["A apojatura","A antecipação","O retardo","A escapada"], a:2, fb:"O retardo é a única nota estranha preparada — é ouvida no acorde anterior antes de tornar-se dissonante. A apojatura chega sem preparação." },
{ q:"Uma melodia com muitas notas estranhas necessita de:", opts:["Muitos acordes diferentes","Um ritmo harmônico mais lento — os ornamentos não exigem novos acordes","Um andamento mais rápido","Somente acordes invertidos"], a:1, fb:"Uma melodia ornamentada pode repousar sobre pouquíssimos acordes. As notas estranhas enriquecem a linha sem mudar a harmonia — daí a importância de identificá-las antes de harmonizar." },
{ q:"A antecipação está geralmente em:", opts:["O tempo forte","O tempo fraco (antes da barra ou da mudança de acorde)","A dominante","O VI grau"], a:1, fb:"A antecipação precede o acorde — está no tempo fraco logo antes da mudança. Ela cria um efeito de leve pressa em direção à nova harmonia." },

{ q:"O esqueleto harmônico é:", opts:["A melodia sozinha","A organização a 3–4 vozes que dá corpo à progressão","A linha do baixo apenas","O acompanhamento rítmico"], a:1, fb:"O esqueleto harmônico é a realização a várias vozes da progressão — antes de qualquer escolha estilística. Ele testa a solidez da estrutura harmônica." },
{ q:"A linha do baixo deve ser sólida nas cadências porque:", opts:["Ela é sempre dobrada","As cadências perfeitas exigem V e I em estado fundamental","Ela toca sempre a quinta","O baixo é sempre oitavado"], a:1, fb:"A cadência perfeita (V→I) exige os dois acordes em estado fundamental. O baixo toca as fundamentais — G e C — para confirmar a resolução sem ambiguidade." },
{ q:"As inversões no baixo servem para:", opts:["Tornar o acorde instável","Criar uma linha de baixo melódica e conjunta","Dobrar a melodia","Evitar dissonâncias"], a:1, fb:"Uma inversão coloca uma terça ou quinta no baixo — permitindo linhas de baixo conjuntas e melódicas em vez de saltos entre fundamentais." },
{ q:"As vozes intermediárias (contralto e tenor) têm como função:", opts:["Dobrar a melodia","Completar o acorde e assegurar a continuidade do tecido polifônico","Criar tensões","Tocar em solo"], a:1, fb:"Contralto e tenor completam o acorde — terça, quinta, sétima conforme o contexto. Seu movimento deve ser fluido e preferencialmente conjunto." },
{ q:"O movimento preferido entre o baixo e as vozes superiores é:", opts:["Paralelo","Contrário — uma voz sobe, a outra desce","Oblíquo sempre","Sempre em terça paralela"], a:1, fb:"O movimento contrário maximiza a independência polifônica e evita naturalmente as paralelas. É o movimento mais equilibrado." },
{ q:"A regra de dobramento em um acorde em estado fundamental é:", opts:["Dobrar a terça","Dobrar a quinta","Dobrar a fundamental (exceto exceções)","Dobrar a sétima"], a:2, fb:"A fundamental é a nota mais estável — dobra-se por padrão. Exceção: VII grau → dobrar sua terça (nunca a sensível)." },
{ q:"Em I6 (primeira inversão de I), o baixo toca:", opts:["A fundamental","A terça","A quinta","A sétima"], a:1, fb:"I6 = primeira inversão: a terça está no baixo. Em Dó maior, C/E tem E (Mi) no baixo." },
{ q:"As notas comuns entre dois acordes devem:", opts:["Ser evitadas","Ser mantidas na mesma voz — elas simplificam a condução de vozes","Subir uma segunda","Ser dobradas"], a:1, fb:"Manter as notas comuns reduz os deslocamentos. Ex: C → Am: C e E são comuns. Mantê-las no lugar fluidifica a escrita." },
{ q:"Qual movimento é proibido entre todas as vozes?", opts:["Os movimentos conjuntos","As quintas e oitavas paralelas","O movimento contrário","Os movimentos disjuntos"], a:1, fb:"As quintas e oitavas paralelas anulam a independência das vozes — dão a ilusão de que duas vozes são uma só. Proibido em escrita estrita." },
{ q:"A sensível (VII grau) deve obrigatoriamente:", opts:["Descer para o VI grau","Subir para a tônica por semitom","Permanecer imóvel","Saltar para a quinta"], a:1, fb:"A sensível sobe obrigatoriamente para a tônica — é a regra absoluta. Em Dó maior: B → C. Esse semitom ascendente é a atração melódica fundamental." },
{ q:"A sétima de dominante (F em G7) deve:", opts:["Subir para G","Descer para E (terça de I) por grau conjunto","Permanecer em F","Saltar para C"], a:1, fb:"A sétima de dominante desce conjuntamente para a terça do acorde seguinte. F → E em G7 → C. Regra absoluta: a sétima de dominante desce." },
{ q:"Qual é a regra sobre o espaçamento entre soprano e contralto?", opts:["Não mais de duas oitavas","Não mais de uma oitava","Exatamente uma terça","Nenhuma regra"], a:1, fb:"Entre soprano e contralto, e entre contralto e tenor: máximo uma oitava. Entre tenor e baixo: até duas oitavas são permitidas." },
{ q:"O princípio 'menos movimentos = melhor escrita' significa:", opts:["Escrever o menor número de notas possível","Usar as notas comuns e os movimentos conjuntos — mover apenas quando necessário","Nunca usar inversões","Todas as vozes permanecem imóveis"], a:1, fb:"Uma boa condução de vozes mantém as notas comuns, avança por graus conjuntos e se move apenas quando musicalmente necessário." },
{ q:"Em I6/4 (segunda inversão de I), o baixo toca:", opts:["A fundamental","A terça","A quinta","A sétima"], a:2, fb:"A 2ª inversão (6/4) coloca a quinta no baixo. C/G em Dó maior: G (Sol) no baixo. É o 6/4 de cadência — ele prepara a dominante." },
{ q:"O dobramento da sétima é:", opts:["Obrigatório","Proibido — a sétima jamais se dobra","Recomendado","Possível em movimento contrário"], a:1, fb:"A sétima jamais se dobra — ela deve resolver conjuntamente para o acorde seguinte. Duas sétimas resolvendo para duas notas idênticas criaria oitavas paralelas." },
{ q:"Qual cruzamento é proibido em escrita a 4 vozes?", opts:["O contralto que ultrapassa momentaneamente o tenor","Nenhum — as vozes podem se cruzar livremente","As vozes nunca devem se cruzar — o soprano permanece sempre acima do contralto, etc.","Somente o baixo pode ultrapassar o tenor"], a:2, fb:"As vozes não se cruzam: S > A > T > B em todo momento. Um cruzamento apaga a independência das vozes e cria confusão polifônica." },
{ q:"Um sobreposição de vozes é:", opts:["Quando duas vozes tocam a mesma nota","Quando uma voz ultrapassa a nota que a voz adjacente acabou de deixar","Quando as vozes tocam em oitava","Quando uma voz salta uma oitava"], a:1, fb:"A sobreposição: A toca uma nota mais alta do que o S acabou de deixar (ou inversamente). Cria confusão sobre a identidade das vozes — proibido em escrita estrita." },
{ q:"A progressão C–Am–F–G é funcionalmente:", opts:["T–T–SD–D","T–D–SD–T","T–T–SD–T","SD–D–T–D"], a:0, fb:"C = tônica (I), Am = tônica (VI), F = subdominante (IV), G = dominante (V). C–Am–F–G = T–T–SD–D — uma progressão muito comum no pop." },
{ q:"Por que o baixo e a melodia não devem frequentemente se confundir?", opts:["Por razões de registro","Porque isso engessa o discurso — perde-se a riqueza do diálogo entre os dois extremos","Porque é proibido","Porque eles tocam sempre em oitavas"], a:1, fb:"Quando baixo e melodia tocam as mesmas notas, perde-se a riqueza do diálogo entre os registros extremos. Um contracanto discreto do baixo é mais vivo do que um dobramento." },
{ q:"Na progressão II–V–I, quais notas de Dm7 se conservam em G7?", opts:["Nenhuma","F e A — F está em G7, A não está em G7 mas pode permanecer","F e C — F está em G7 (sétima) e C pode descer para B","D e A"], a:2, fb:"Dm7 = D–F–A–C. G7 = G–B–D–F. Notas comuns: D e F. F permanece como sétima de G7. D permanece como quinta de G7. A e C movem-se para G e B." },
{ q:"Uma cadência perfeita exige:", opts:["Pelo menos um acorde invertido","V e I em estado fundamental (fundamentais no baixo)","O VII grau","Um acorde de sexta"], a:1, fb:"A cadência perfeita requer V e I em estado fundamental — as fundamentais G e C no baixo. Qualquer inversão a transforma em cadência imperfeita." },
{ q:"O 6/4 de cadência (I6/4) é usado:", opts:["No lugar da dominante","Logo antes da dominante — ele prepara V7 como uma dupla apojatura","Como tônica final","Na abertura de cada frase"], a:1, fb:"O 6/4 de cadência (C/G) precede G7 — suas notas G e E são a quinta e a terça de G7. Ele atua como uma dupla apojatura ascendente da quinta e da terça da dominante." },
{ q:"A tessitura do soprano em escrita SATB é:", opts:["G3 a C5","C4 a G5","C3 a G4","E2 a C4"], a:1, fb:"Soprano: C4 (Dó médio) a G5. Contralto: G3 a C5. Tenor: C3 a G4. Baixo: E2 a C4. Essas tessituras garantem o conforto vocal e o equilíbrio acústico." },
{ q:"O que é uma quinta direta (ou quinta de movimento direto)?", opts:["Duas vozes formando uma quinta por movimento conjunto","Duas vozes externas (S e B) atingindo uma quinta por movimento direto (mesma direção)","Duas quintas consecutivas","Uma quinta diminuta"], a:1, fb:"A quinta direta: soprano e baixo movem-se na mesma direção e chegam a uma quinta. É proibida entre as vozes externas — tolerada apenas se o soprano avança por grau conjunto." },
{ q:"A progressão I–V6–I6–IV–V7–I usa inversões para:", opts:["Tornar os acordes instáveis","Criar uma linha de baixo ascendente conjunta: C–B–C–F–G–C","Evitar a dominante","Dobrar a melodia"], a:1, fb:"V6 = G/B, I6 = C/E. Baixo: C→B→C→F→G→C — linha melódica variada e interessante graças às inversões." },

{ q:"O acompanhamento é construído a partir de:", opts:["Nada — ele é improvisado livremente","O esqueleto harmônico, do qual é a forma expressiva","A melodia apenas","O ritmo apenas"], a:1, fb:"O acompanhamento se apoia no esqueleto harmônico — é a sua tradução estilística. Ele sustenta e amplifica a curva de tensão musical." },
{ q:"O arpejo se caracteriza por:", opts:["Acordes tocados simultaneamente","O desdobramento regular das notas do acorde no tempo","Síncopes rítmicas","Contrapontos independentes"], a:1, fb:"O arpejo desdobra as notas do acorde no tempo — em vez de simultaneamente. Ele cria uma continuidade fluida característica das baladas e noturnos." },
{ q:"O comping é proveniente do:", opts:["Barroco","Classicismo vienense","Jazz — acordes pontuais nos contratempos com muito silêncio","Romantismo"], a:2, fb:"O comping é uma técnica do jazz — acordes curtos, sincopados, com silêncio expressivo. O espaço entre os acordes é tão importante quanto os próprios acordes." },
{ q:"Qual parâmetro aumenta a tensão em um acompanhamento?", opts:["Menos notas","Um andamento mais lento","Mais densidade — mais notas e ritmos mais rápidos","Um âmbito restrito"], a:2, fb:"A tensão aumenta com a densidade — mais notas por compasso, síncopes, ritmo harmônico rápido, âmbito largo." },
{ q:"O âmbito de um acompanhamento designa:", opts:["O número de vozes","A distância entre a nota mais grave e a nota mais aguda","O registro médio","A duração de cada nota"], a:1, fb:"O âmbito é a extensão do acompanhamento. Largo = tensão dramática. Restrito = compressão dinâmica e atmosfera íntima." },
{ q:"As notas estranhas no acompanhamento:", opts:["Enfraquecem a harmonia","Criam intensidade — retardos, apojaturas adicionam dissonâncias expressivas resolvidas","Devem ser evitadas","Não têm nenhum efeito"], a:1, fb:"As notas estranhas enriquecem o acompanhamento — um retardo ou uma apojatura cria uma microtensão que se resolve, adicionando expressão a cada acorde." },
{ q:"O estilo baixo–acorde separado é típico de:", opts:["A fuga barroca","A valsa — baixo no 1, acorde no 2 e 3","O noturno romântico","A tocata"], a:1, fb:"A valsa usa baixo(1)–acorde(2)–acorde(3). Esse padrão ancora o primeiro tempo e cria o balanço característico." },
{ q:"Um acompanhamento em contraponto exige:", opts:["Pouco conhecimento em harmonia","O domínio da condução de vozes — cada linha é melodicamente autônoma","Apenas acordes simultâneos","Improvisação"], a:1, fb:"O contraponto trata cada voz como uma linha independente. É a forma mais complexa — exige um domínio total da condução de vozes." },
{ q:"Um bom acompanhamento nunca contradiz:", opts:["O andamento","A curva de tensão musical da melodia","A tonalidade","O registro do cantor"], a:1, fb:"O acompanhamento deve ser coerente com a dinâmica de tensão da melodia — ele a anuncia, a acompanha ou a prolonga." },
{ q:"A repetição de um motivo no acompanhamento cria:", opts:["Tensão","Estabilidade — a repetição ancora e tranquiliza o ouvido","Surpresa","Desordem"], a:1, fb:"A repetição de um motivo cria estabilidade — o ouvido reconhece e antecipa. A variação do motivo cria tensão." },
];

